import * as pdfjsLib from 'pdfjs-dist';
// @ts-ignore
import { jsPDF } from 'jspdf';

// Initialize PDF worker
if (pdfjsLib.GlobalWorkerOptions) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://esm.sh/pdfjs-dist@3.11.174/build/pdf.worker.min.js';
}

export const getPdfPreview = async (file: File): Promise<{ url: string, width: number, height: number }> => {
  try {
    const arrayBuffer = await file.arrayBuffer();
    // Load the PDF file
    const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
    const pdf = await loadingTask.promise;

    // Get the first page
    const page = await pdf.getPage(1);
    const viewport = page.getViewport({ scale: 1.0 });

    // Create canvas to render
    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');

    // Set dimensions to match PDF page
    canvas.width = viewport.width;
    canvas.height = viewport.height;

    if (!context) throw new Error("Canvas context not available");

    // Render PDF page into canvas context
    const renderContext = {
      canvasContext: context,
      viewport: viewport
    };

    await page.render(renderContext).promise;

    return {
      url: canvas.toDataURL('image/jpeg'),
      width: viewport.width,
      height: viewport.height
    };
  } catch (error) {
    console.error("Error generating PDF preview:", error);
    throw error;
  }
};

export const compressPdf = async (file: File, options: ProcessingOptions): Promise<Blob> => {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const numPages = pdf.numPages;

  // Create new PDF document
  // We'll set orientation/size per page loop
  const newPdf = new jsPDF({
    orientation: 'p',
    unit: 'px',
    format: 'a4', // Default, will change per page
    compress: true 
  });

  // Remove the default initial page so we can add our own sized pages
  newPdf.deletePage(1);

  for (let i = 1; i <= numPages; i++) {
    const page = await pdf.getPage(i);

    // Determine scale based on resize mode
    // "Original" for PDF usually means we want to rasterize at a decent quality
    // We'll use 1.0 as base, but if user asked for percentage or fixed width, we apply it.
    let scale = 1.0;

    // Get natural viewport
    const originalViewport = page.getViewport({ scale: 1.0 });

    if (options.resizeMode === 'percentage') {
       scale = options.resizeValue / 100;
    } else if (options.resizeMode === 'fixed-width') {
       scale = options.resizeValue / originalViewport.width;
    } else if (options.resizeMode === 'fixed-height') {
       scale = options.resizeValue / originalViewport.height;
    }

    // Limit minimum scale to avoid total blurred mess if accidental
    scale = Math.max(0.1, scale);

    const viewport = page.getViewport({ scale });

    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');
    canvas.width = viewport.width;
    canvas.height = viewport.height;

    if (!context) continue;

    // Use white background for transparent PDFs
    context.fillStyle = '#FFFFFF';
    context.fillRect(0, 0, canvas.width, canvas.height);

    await page.render({ canvasContext: context, viewport }).promise;

    // Convert to compressed JPEG data URL
    const imgData = canvas.toDataURL('image/jpeg', options.quality);

    // Add page to new PDF
    newPdf.addPage([viewport.width, viewport.height], viewport.width > viewport.height ? 'l' : 'p');
    newPdf.addImage(imgData, 'JPEG', 0, 0, viewport.width, viewport.height);
  }

  return newPdf.output('blob');
};

