export type ImageFormat = 'image/jpeg' | 'image/png' | 'image/webp';

export type ResizeMode = 'original' | 'percentage' | 'fixed-width' | 'fixed-height';

export type AppMode = 'image' | 'pdf';

export interface ProcessingOptions {
  format: ImageFormat;
  quality: number; // 0.1 to 1.0
  resizeMode: ResizeMode;
  resizeValue: number; // Percentage (1-100) or pixels
  maintainAspectRatio: boolean;
}

export type ProcessStatus = 'idle' | 'processing' | 'completed' | 'error';

export interface ImageItem {
  id: string;
  file: File;
  previewUrl: string;
  originalSize: number;
  originalWidth: number;
  originalHeight: number;
  status: ProcessStatus;
  processedUrl?: string;
  processedSize?: number;
  processedWidth?: number;
  processedHeight?: number;
  error?: string;
}

import { ProcessingOptions } from '../types';
// @ts-ignore
import * as pdfjsLib from 'pdfjs-dist';
// @ts-ignore
import { jsPDF } from 'jspdf';

// Initialize PDF worker with version matching package.json/importmap
if (pdfjsLib.GlobalWorkerOptions) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://esm.sh/pdfjs-dist@5.4.449/build/pdf.worker.min.js';
}

export const getPdfPreview = async (file: File): Promise<{ url: string, width: number, height: number }> => {
  try {
    const arrayBuffer = await file.arrayBuffer();
    // Load the PDF file
    const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
    const pdf = await loadingTask.promise;

    // Get the first page
    const page = await pdf.getPage(1);
    const viewport = page.getViewport({ scale: 1.0 });

    // Create canvas to render
    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');

    // Set dimensions to match PDF page
    canvas.width = viewport.width;
    canvas.height = viewport.height;

    if (!context) throw new Error("Canvas context not available");

    // Render PDF page into canvas context
    const renderContext = {
      canvasContext: context,
      viewport: viewport
    };

    // Cast to any to avoid RenderParameters type mismatch (missing canvas property in strict types)
    await page.render(renderContext as any).promise;

    return {
      url: canvas.toDataURL('image/jpeg'),
      width: viewport.width,
      height: viewport.height
    };
  } catch (error) {
    console.error("Error generating PDF preview:", error);
    throw error;
  }
};

export const compressPdf = async (file: File, options: ProcessingOptions): Promise<Blob> => {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const numPages = pdf.numPages;

  // Create new PDF document
  // We'll set orientation/size per page loop
  const newPdf = new jsPDF({
    orientation: 'p',
    unit: 'px',
    format: 'a4', // Default, will change per page
    compress: true 
  });

  // Remove the default initial page so we can add our own sized pages
  newPdf.deletePage(1);

  for (let i = 1; i <= numPages; i++) {
    const page = await pdf.getPage(i);

    // Determine scale based on resize mode
    // "Original" for PDF usually means we want to rasterize at a decent quality
    // We'll use 1.0 as base, but if user asked for percentage or fixed width, we apply it.
    let scale = 1.0;

    // Get natural viewport
    const originalViewport = page.getViewport({ scale: 1.0 });

    if (options.resizeMode === 'percentage') {
       scale = options.resizeValue / 100;
    } else if (options.resizeMode === 'fixed-width') {
       scale = options.resizeValue / originalViewport.width;
    } else if (options.resizeMode === 'fixed-height') {
       scale = options.resizeValue / originalViewport.height;
    }

    // Limit minimum scale to avoid total blurred mess if accidental
    scale = Math.max(0.1, scale);

    const viewport = page.getViewport({ scale });

    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');
    canvas.width = viewport.width;
    canvas.height = viewport.height;

    if (!context) continue;

    // Use white background for transparent PDFs
    context.fillStyle = '#FFFFFF';
    context.fillRect(0, 0, canvas.width, canvas.height);

    // Cast to any to avoid RenderParameters type mismatch
    await page.render({ canvasContext: context, viewport } as any).promise;

    // Convert to compressed JPEG data URL
    const imgData = canvas.toDataURL('image/jpeg', options.quality);

    // Add page to new PDF
    newPdf.addPage([viewport.width, viewport.height], viewport.width > viewport.height ? 'l' : 'p');
    newPdf.addImage(imgData, 'JPEG', 0, 0, viewport.width, viewport.height);
  }

  return newPdf.output('blob');
};

import React, { useCallback, useState } from 'react';
import { Upload, FileImage, FileText } from 'lucide-react';
import { AppMode } from '../types';

interface DropzoneProps {
  onFilesDropped: (files: File[]) => void;
  className?: string;
  isCompact?: boolean;
  mode: AppMode;
}

const Dropzone: React.FC<DropzoneProps> = ({ onFilesDropped, className = '', isCompact = false, mode }) => {
  const [isDragging, setIsDragging] = useState(false);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
  }, []);

  const isValidFile = (file: File) => {
    const type = file.type.toLowerCase();
    const name = file.name.toLowerCase();

    if (mode === 'pdf') {
        return type === 'application/pdf' || name.endsWith('.pdf');
    }

    // Image mode
    return type.startsWith('image/') || 
           name.endsWith('.heic') || 
           name.endsWith('.heif');
  };

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault();
      e.stopPropagation();
      setIsDragging(false);

      const files = Array.from(e.dataTransfer.files).filter(isValidFile);
      if (files.length > 0) {
        onFilesDropped(files);
      }
    },
    [onFilesDropped, mode]
  );

  const handleFileInput = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files.length > 0) {
        const files = Array.from(e.target.files).filter(isValidFile);
        onFilesDropped(files);
      }
      // Reset value so same files can be selected again
      e.target.value = '';
    },
    [onFilesDropped, mode]
  );

  const acceptString = mode === 'pdf' ? '.pdf' : 'image/*,.heic,.heif';

  if (isCompact) {
     return (
        <div
            className={`relative flex items-center justify-center border-2 border-dashed rounded-lg transition-colors cursor-pointer p-4 ${
            isDragging
                ? 'border-blue-500 bg-blue-500/10'
                : 'border-slate-700 hover:border-slate-500 hover:bg-slate-800/50'
            } ${className}`}
            onDragOver={handleDragOver}
            onDragLeave={handleDragLeave}
            onDrop={handleDrop}
        >
            <input
                type="file"
                multiple
                accept={acceptString}
                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                onChange={handleFileInput}
            />
            <div className="flex flex-col items-center text-center space-y-2">
                <Upload className="w-6 h-6 text-slate-400" />
                <span className="text-xs text-slate-400 font-medium">Add {mode === 'pdf' ? 'PDFs' : 'Images'}</span>
            </div>
        </div>
     )
  }

  return (
    <div
      className={`relative flex flex-col items-center justify-center w-full h-full min-h-[300px] border-2 border-dashed rounded-xl transition-all cursor-pointer ${
        isDragging
          ? 'border-blue-500 bg-blue-500/10 scale-[0.99]'
          : 'border-slate-700 hover:border-slate-500 hover:bg-slate-800/30'
      } ${className}`}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
    >
      <input
        type="file"
        multiple
        accept={acceptString}
        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
        onChange={handleFileInput}
      />
      <div className="flex flex-col items-center text-center space-y-4 p-8 pointer-events-none">
        <div className={`p-4 rounded-full bg-slate-800/50 ${isDragging ? 'text-blue-400' : 'text-slate-400'}`}>
            {isDragging ? <Upload className="w-12 h-12" /> : (
              <div className="relative">
                 {mode === 'pdf' ? <FileText className="w-12 h-12" /> : <FileImage className="w-12 h-12" />}
              </div>
            )}
        </div>
        <div className="space-y-1">
          <p className="text-xl font-semibold text-slate-200">
            {isDragging ? 'Drop files here' : 'Drag & drop files'}
          </p>
          <p className="text-sm text-slate-400">
            {mode === 'pdf' ? 'PDF Documents' : 'Images (JPG, PNG, WebP, HEIC)'}
          </p>
        </div>
        <div className="pt-4 flex flex-wrap justify-center gap-2">
            {mode === 'pdf' ? (
                <span className="px-2 py-1 rounded bg-slate-800 border border-slate-700 text-xs text-slate-400">PDF</span>
            ) : (
                <>
                <span className="px-2 py-1 rounded bg-slate-800 border border-slate-700 text-xs text-slate-400">JPG</span>
                <span className="px-2 py-1 rounded bg-slate-800 border border-slate-700 text-xs text-slate-400">PNG</span>
                <span className="px-2 py-1 rounded bg-slate-800 border border-slate-700 text-xs text-slate-400">WebP</span>
                <span className="px-2 py-1 rounded bg-slate-800 border border-slate-700 text-xs text-slate-400">HEIC</span>
                </>
            )}
        </div>
      </div>
    </div>
  );
};

export default Dropzone;

import React from 'react';
import { Settings, Sliders, Image as ImageIcon, Type, Activity, FileText } from 'lucide-react';
import { ProcessingOptions, ResizeMode, ImageFormat, AppMode } from '../types';
import { SUPPORTED_FORMATS } from '../constants';

interface SettingsPanelProps {
  options: ProcessingOptions;
  onOptionsChange: (newOptions: ProcessingOptions) => void;
  disabled?: boolean;
  onProcess: () => void;
  isProcessing: boolean;
  hasFiles: boolean;
  mode: AppMode;
}

const SettingsPanel: React.FC<SettingsPanelProps> = ({
  options,
  onOptionsChange,
  disabled = false,
  onProcess,
  isProcessing,
  hasFiles,
  mode,
}) => {
  const handleChange = <K extends keyof ProcessingOptions>(
    key: K,
    value: ProcessingOptions[K]
  ) => {
    onOptionsChange({ ...options, [key]: value });
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 border-r border-slate-800 w-80 shrink-0 overflow-y-auto custom-scrollbar">
      <div className="p-6 border-b border-slate-800">
        <h2 className="text-lg font-bold text-white flex items-center gap-2">
          <Settings className="w-5 h-5 text-blue-500" />
          {mode === 'pdf' ? 'PDF Settings' : 'Image Settings'}
        </h2>
        <p className="text-xs text-slate-400 mt-1">
          Adjust settings for all files
        </p>
      </div>

      <div className="p-6 space-y-8 flex-1">
        {/* Resize Section */}
        <section className="space-y-4">
          <div className="flex items-center gap-2 text-sm font-medium text-slate-300">
            {mode === 'pdf' ? <FileText className="w-4 h-4 text-blue-400" /> : <ImageIcon className="w-4 h-4 text-blue-400" />}
            {mode === 'pdf' ? 'PAGE SCALING' : 'RESIZE'}
          </div>

          <div className="grid grid-cols-2 gap-2">
            {(['original', 'percentage', 'fixed-width', 'fixed-height'] as ResizeMode[]).map((m) => (
              <button
                key={m}
                onClick={() => handleChange('resizeMode', m)}
                disabled={disabled}
                className={`px-3 py-2 text-xs font-medium rounded-lg border transition-all ${
                  options.resizeMode === m
                    ? 'bg-blue-600 border-blue-500 text-white'
                    : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-600'
                }`}
              >
                {m.replace('-', ' ').toUpperCase()}
              </button>
            ))}
          </div>

          {options.resizeMode !== 'original' && (
            <div className="space-y-3 p-4 bg-slate-800/50 rounded-lg border border-slate-700/50">
              <label className="text-xs text-slate-400">
                {options.resizeMode === 'percentage' ? 'Scale Percentage' : 'Target Pixels'}
              </label>
              <div className="flex items-center gap-3">
                <input
                  type="range"
                  min={options.resizeMode === 'percentage' ? 10 : 100}
                  max={options.resizeMode === 'percentage' ? 200 : 4000}
                  step={options.resizeMode === 'percentage' ? 5 : 50}
                  value={options.resizeValue}
                  disabled={disabled}
                  onChange={(e) => handleChange('resizeValue', Number(e.target.value))}
                  className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                />
                <span className="text-sm font-mono text-white min-w-[3rem] text-right">
                  {options.resizeValue}{options.resizeMode === 'percentage' ? '%' : 'px'}
                </span>
              </div>
              <label className="flex items-center gap-2 cursor-pointer group">
                  <input 
                      type="checkbox"
                      checked={options.maintainAspectRatio}
                      onChange={(e) => handleChange('maintainAspectRatio', e.target.checked)}
                      disabled={disabled}
                      className="rounded border-slate-600 bg-slate-700 text-blue-500 focus:ring-offset-slate-900"
                  />
                  <span className="text-xs text-slate-400 group-hover:text-slate-300">Maintain aspect ratio</span>
              </label>
            </div>
          )}
          {mode === 'pdf' && (
             <p className="text-[10px] text-slate-500 italic">
                Note: Pages will be converted to images and resized.
             </p>
          )}
        </section>

        {/* Format Section - Hide for PDF */}
        {mode === 'image' && (
            <section className="space-y-4">
            <div className="flex items-center gap-2 text-sm font-medium text-slate-300">
                <Type className="w-4 h-4 text-purple-400" />
                OUTPUT FORMAT
            </div>
            <div className="grid grid-cols-1 gap-2">
                <select
                value={options.format}
                onChange={(e) => handleChange('format', e.target.value as ImageFormat)}
                disabled={disabled}
                className={`w-full px-3 py-2 bg-slate-800 border border-slate-700 rounded-lg text-sm text-white focus:outline-none focus:border-blue-500`}
                >
                {Object.entries(SUPPORTED_FORMATS).map(([value, label]) => (
                    <option key={value} value={value}>
                    {label}
                    </option>
                ))}
                </select>
            </div>
            </section>
        )}

        {/* Quality Section */}
        <section className="space-y-4">
          <div className="flex items-center gap-2 text-sm font-medium text-slate-300">
            <Sliders className="w-4 h-4 text-green-400" />
            COMPRESSION QUALITY
          </div>

          <div className="space-y-3 p-4 bg-slate-800/50 rounded-lg border border-slate-700/50">
             <div className="flex justify-between items-center">
                 <span className="text-xs text-slate-400">Low Quality</span>
                 <span className="text-xs text-slate-400">High Quality</span>
             </div>
            <div className="flex items-center gap-3">
                <input
                  type="range"
                  min="0.1"
                  max="1.0"
                  step="0.05"
                  value={options.quality}
                  disabled={disabled || (mode === 'image' && options.format === 'image/png')}
                  onChange={(e) => handleChange('quality', Number(e.target.value))}
                  className={`w-full h-1.5 rounded-lg appearance-none cursor-pointer accent-blue-500 ${mode === 'image' && options.format === 'image/png' ? 'bg-slate-700 opacity-50' : 'bg-slate-700'}`}
                />
                <span className="text-sm font-mono text-white min-w-[3rem] text-right">
                  {Math.round(options.quality * 100)}%
                </span>
            </div>
            {mode === 'image' && options.format === 'image/png' && (
                <p className="text-[10px] text-yellow-500/80">
                    * PNG is lossless. Quality setting may not apply.
                </p>
            )}
          </div>
        </section>
      </div>

      <div className="p-6 border-t border-slate-800 bg-slate-900 sticky bottom-0 z-10">
        <button
          onClick={onProcess}
          disabled={disabled || !hasFiles || isProcessing}
          className={`w-full py-3.5 px-4 rounded-xl flex items-center justify-center gap-2 font-bold transition-all shadow-lg ${
            isProcessing
              ? 'bg-slate-700 text-slate-400 cursor-not-allowed'
              : !hasFiles
              ? 'bg-slate-800 text-slate-500 cursor-not-allowed'
              : 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white shadow-blue-500/20 active:scale-[0.98]'
          }`}
        >
          {isProcessing ? (
             <Activity className="w-5 h-5 animate-spin" />
          ) : (
             <Activity className="w-5 h-5" />
          )}
          {isProcessing ? 'Processing...' : `Process ${mode === 'pdf' ? 'PDFs' : 'Images'}`}
        </button>
      </div>
    </div>
  );
};

export default SettingsPanel;

import React, { useState, useCallback, useEffect } from 'react';
import { Layers, Download, Trash2, Loader2, Image as ImageIcon, CheckCircle2, TrendingDown, FileText } from 'lucide-react';
import SettingsPanel from './components/SettingsPanel';
import Dropzone from './components/Dropzone';
import ImageItem from './components/ImageItem';
import { ProcessingOptions, ImageItem as ImageItemType, AppMode } from './types';
import { DEFAULT_OPTIONS } from './constants';
import { generateId, processFile, isHeic, convertHeicToJpeg } from './utils/imageUtils';
import { getPdfPreview, compressPdf } from './utils/pdfUtils';
// @ts-ignore
import JSZip from 'jszip';

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('image');
  const [files, setFiles] = useState<ImageItemType[]>([]);
  const [options, setOptions] = useState<ProcessingOptions>(DEFAULT_OPTIONS);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isZipping, setIsZipping] = useState(false);
  const [uploadProgress, setUploadProgress] = useState<{ current: number; total: number } | null>(null);

  // Clean up object URLs to prevent memory leaks
  useEffect(() => {
    return () => {
      files.forEach((file) => {
        URL.revokeObjectURL(file.previewUrl);
        if (file.processedUrl) URL.revokeObjectURL(file.processedUrl);
      });
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); 

  const handleModeChange = (newMode: AppMode) => {
    if (newMode === mode) return;
    if (files.length > 0) {
        if (!window.confirm("Switching modes will clear your current file list. Continue?")) {
            return;
        }
    }
    handleClearAll();
    setMode(newMode);
  };

  const handleFilesDropped = useCallback(async (newFiles: File[]) => {
    setUploadProgress({ current: 0, total: newFiles.length });
    let processedCount = 0;

    // Process one by one to avoid blocking and update UI incrementally
    for (const file of newFiles) {
      try {
          let fileToProcess = file;
          let previewUrl = '';
          let width = 0;
          let height = 0;

          if (mode === 'pdf') {
              // PDF Handling
              if (file.type !== 'application/pdf' && !file.name.endsWith('.pdf')) {
                  console.warn(`Skipped non-pdf file in PDF mode: ${file.name}`);
                  continue;
              }
              try {
                const preview = await getPdfPreview(file);
                previewUrl = preview.url;
                width = preview.width;
                height = preview.height;
             } catch (e) {
                 console.error(`Failed to generate PDF preview: ${file.name}`, e);
                 // Fallback or skip? Let's skip for safety or use a placeholder if we had one
                 processedCount++;
                 setUploadProgress({ current: processedCount, total: newFiles.length });
                 continue;
             }

          } else {
              // Image Handling
              if (isHeic(file)) {
                try {
                    fileToProcess = await convertHeicToJpeg(file);
                    previewUrl = URL.createObjectURL(fileToProcess);
                } catch (e) {
                    console.error(`Failed to convert HEIC file: ${file.name}`, e);
                    continue; 
                }
              } else {
                previewUrl = URL.createObjectURL(fileToProcess);
              }

              // Get dimensions
              try {
                const img = await new Promise<HTMLImageElement>((resolve, reject) => {
                    const i = new Image();
                    i.onload = () => resolve(i);
                    i.onerror = reject;
                    i.src = previewUrl;
                });
                width = img.naturalWidth;
                height = img.naturalHeight;
              } catch (e) {
                  // If image fails to load, we might still process it blindly, 
                  // but previewUrl is likely bad.
                  console.warn("Failed to load image for dimensions", e);
              }
          }

          const newItem: ImageItemType = {
            id: generateId(),
            file: fileToProcess,
            previewUrl,
            originalSize: file.size,
            originalWidth: width,
            originalHeight: height,
            status: 'idle',
          };

          setFiles((prev) => [...prev, newItem]);

      } catch (err) {
          console.error("Error processing dropped file", err);
      } finally {
        processedCount++;
        setUploadProgress({ current: processedCount, total: newFiles.length });
      }
    }

    setTimeout(() => {
        setUploadProgress(null);
    }, 500);
  }, [mode]);

  const handleRemoveFile = useCallback((id: string) => {
    setFiles((prev) => {
      const fileToRemove = prev.find((f) => f.id === id);
      if (fileToRemove) {
        URL.revokeObjectURL(fileToRemove.previewUrl);
        if (fileToRemove.processedUrl) URL.revokeObjectURL(fileToRemove.processedUrl);
      }
      return prev.filter((f) => f.id !== id);
    });
  }, []);

  const handleClearAll = useCallback(() => {
    files.forEach((f) => {
      URL.revokeObjectURL(f.previewUrl);
      if (f.processedUrl) URL.revokeObjectURL(f.processedUrl);
    });
    setFiles([]);
  }, [files]);

  const handleProcessAll = useCallback(async () => {
    setIsProcessing(true);

    // Only process idle or error files
    const itemsToProcess = files.filter(f => f.status === 'idle' || f.status === 'error');

    for (const item of itemsToProcess) {
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing', error: undefined } : f));

      let result: Partial<ImageItemType>;

      try {
         if (mode === 'pdf') {
             const pdfBlob = await compressPdf(item.file, options);
             const processedUrl = URL.createObjectURL(pdfBlob);

             // Rough est of output dims logic matching pdfUtils
             let processedWidth = item.originalWidth;
             let processedHeight = item.originalHeight;
             if (options.resizeMode === 'percentage') {
                processedWidth = Math.round(item.originalWidth * (options.resizeValue / 100));
                processedHeight = Math.round(item.originalHeight * (options.resizeValue / 100));
             } else if (options.resizeMode === 'fixed-width') {
                processedWidth = options.resizeValue;
                processedHeight = Math.round(options.resizeValue * (item.originalHeight / item.originalWidth));
             } else if (options.resizeMode === 'fixed-height') {
                processedHeight = options.resizeValue;
                processedWidth = Math.round(options.resizeValue * (item.originalWidth / item.originalHeight));
             }

             result = {
                status: 'completed',
                processedUrl,
                processedSize: pdfBlob.size,
                processedWidth,
                processedHeight,
                error: undefined
             };
         } else {
             result = await processFile(item, options);
         }
      } catch (err: any) {
         result = { status: 'error', error: err.message || 'Processing failed' };
      }

      setFiles(prev => {
          const fileExists = prev.some(f => f.id === item.id);
          if (!fileExists) {
              if (result.processedUrl) URL.revokeObjectURL(result.processedUrl);
              return prev;
          }

          return prev.map(f => {
            if (f.id === item.id) {
                if (f.processedUrl && f.processedUrl !== result.processedUrl) {
                    URL.revokeObjectURL(f.processedUrl);
                }
                return { ...f, ...result };
            }
            return f;
          });
      });
    }

    setIsProcessing(false);
  }, [files, options, mode]);

  const handleDownloadAll = useCallback(async () => {
    setIsZipping(true);
    try {
        const zip = new JSZip();

        const processedFiles = files.filter(f => f.status === 'completed' && f.processedUrl);

        if (processedFiles.length === 0) {
            setIsZipping(false);
            return;
        }

        const usedNames: Record<string, number> = {};

        for (const file of processedFiles) {
             if (!file.processedUrl) continue;

             try {
                const response = await fetch(file.processedUrl);
                const blob = await response.blob();

                let ext = 'jpg'; // default
                if (mode === 'pdf') {
                    ext = 'pdf';
                } else if (blob.type === 'image/png') {
                    ext = 'png';
                } else if (blob.type === 'image/webp') {
                    ext = 'webp';
                }

                let baseName = file.file.name.substring(0, file.file.name.lastIndexOf('.')) || file.file.name;
                // Add suffix
                let fileName = `${baseName}_optimized.${ext}`;

                if (usedNames[fileName]) {
                    usedNames[fileName]++;
                    fileName = `${baseName}_optimized_${usedNames[fileName]}.${ext}`;
                } else {
                    usedNames[fileName] = 1;
                }

                zip.file(fileName, blob);
             } catch (e) {
                 console.error(`Failed to add file ${file.file.name} to zip`, e);
             }
        }

        const content = await zip.generateAsync({ type: "blob" });
        const url = URL.createObjectURL(content);
        const link = document.createElement('a');
        link.href = url;
        link.download = "OptiBatch.zip";
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);

    } catch (error) {
        console.error("Zip failed", error);
        alert("Failed to create zip file.");
    } finally {
        setIsZipping(false);
    }
  }, [files, mode]);

  const stats = {
    total: files.length,
    completed: files.filter(f => f.status === 'completed').length,
    savedBytes: files.reduce((acc, curr) => {
        if (curr.status === 'completed' && curr.processedSize) {
            return acc + (curr.originalSize - curr.processedSize);
        }
        return acc;
    }, 0)
  };

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden relative">

      {/* Sidebar Options */}
      <SettingsPanel
        options={options}
        onOptionsChange={setOptions}
        disabled={isProcessing || files.length === 0}
        onProcess={handleProcessAll}
        isProcessing={isProcessing}
        hasFiles={files.length > 0}
        mode={mode}
      />

      {/* Main Content */}
      <div className="flex-1 flex flex-col min-w-0 h-full">
        {/* Header */}
        <header className="flex items-center justify-between px-8 py-4 border-b border-slate-800 bg-slate-950/50 backdrop-blur-sm z-10">
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-3">
                <div className="p-2 bg-blue-600 rounded-lg shadow-lg shadow-blue-500/20">
                <Layers className="w-6 h-6 text-white" />
                </div>
                <div>
                <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
                    OptiBatch
                </h1>
                <p className="text-xs text-slate-500 font-medium">Bulk Processor</p>
                </div>
            </div>

            {/* Mode Switcher Tabs */}
            <div className="flex p-1 bg-slate-800/50 rounded-lg border border-slate-700/50 ml-4">
                <button
                    onClick={() => handleModeChange('image')}
                    className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-all ${
                        mode === 'image' 
                        ? 'bg-slate-700 text-white shadow-sm' 
                        : 'text-slate-400 hover:text-slate-200'
                    }`}
                >
                    <ImageIcon className="w-4 h-4" />
                    Images
                </button>
                <button
                    onClick={() => handleModeChange('pdf')}
                    className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-all ${
                        mode === 'pdf' 
                        ? 'bg-slate-700 text-white shadow-sm' 
                        : 'text-slate-400 hover:text-slate-200'
                    }`}
                >
                    <FileText className="w-4 h-4" />
                    PDFs
                </button>
            </div>
          </div>

          <div className="flex items-center gap-4">
             {/* Stats Indicators */}
             {files.length > 0 && (
                <div className="hidden md:flex items-center gap-3 text-xs font-medium text-slate-400 mr-2 animate-in fade-in slide-in-from-top-4 duration-300">
                    <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-800/50 border border-slate-700/50 rounded-lg shadow-sm backdrop-blur-sm">
                        {mode === 'pdf' ? <FileText className="w-3.5 h-3.5 text-blue-400" /> : <ImageIcon className="w-3.5 h-3.5 text-blue-400" />}
                        <span>Files: <span className="text-white font-bold ml-0.5">{stats.total}</span></span>
                    </div>

                    {stats.completed > 0 && (
                        <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-800/50 border border-slate-700/50 rounded-lg shadow-sm backdrop-blur-sm">
                            <CheckCircle2 className="w-3.5 h-3.5 text-green-400" />
                            <span>Done: <span className="text-white font-bold ml-0.5">{stats.completed}</span></span>
                        </div>
                    )}

                    {stats.savedBytes > 0 && (
                         <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-800/50 border border-slate-700/50 rounded-lg shadow-sm backdrop-blur-sm">
                            <TrendingDown className="w-3.5 h-3.5 text-emerald-400" />
