import { ProcessingOptions } from '../types';
// @ts-ignore
import * as pdfjsLib from 'pdfjs-dist';
// @ts-ignore
import { jsPDF } from 'jspdf';

// Initialize PDF worker with version matching importmap
if (pdfjsLib.GlobalWorkerOptions) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://esm.sh/pdfjs-dist@3.11.174/build/pdf.worker.min.js';
}

export const getPdfPreview = async (file: File): Promise<{ url: string, width: number, height: number }> => {
  try {
    const arrayBuffer = await file.arrayBuffer();
    const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
    const pdf = await loadingTask.promise;

    const page = await pdf.getPage(1);
    const viewport = page.getViewport({ scale: 1.0 });

    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');

    canvas.width = viewport.width;
    canvas.height = viewport.height;

    if (!context) throw new Error("Canvas context not available");

    const renderContext = {
      canvasContext: context,
      viewport: viewport
    };

    await page.render(renderContext as any).promise;

    return {
      url: canvas.toDataURL('image/jpeg'),
      width: viewport.width,
      height: viewport.height
    };
  } catch (error) {
    console.error("Error generating PDF preview:", error);
    throw error;
  }
};

export const compressPdf = async (file: File, options: ProcessingOptions): Promise<Blob> => {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const numPages = pdf.numPages;

  // Create new PDF document using points (standard PDF unit)
  const newPdf = new jsPDF({
    orientation: 'p',
    unit: 'pt',
    compress: true 
  });

  // Remove default page
  newPdf.deletePage(1);

  for (let i = 1; i <= numPages; i++) {
    const page = await pdf.getPage(i);

    // 1. Get original physical dimensions in points (72 DPI)
    // This preserves the "paper size" (A4, Letter, etc.)
    const originalViewport = page.getViewport({ scale: 1.0 });

    // 2. Determine rasterization scale based on target DPI
    // Standard PDF is 72 DPI. 
    // If target is 144 DPI (Ebook), scale = 2.0.
    // If target is 72 DPI (Screen), scale = 1.0.
    const targetDpi = options.pdfDpi || 144;
    const rasterScale = targetDpi / 72;

    // 3. Get viewport for the actual pixel rendering (high res or low res)
    const rasterViewport = page.getViewport({ scale: rasterScale });

    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');
    canvas.width = rasterViewport.width;
    canvas.height = rasterViewport.height;

    if (!context) continue;

    // White background for transparency
    context.fillStyle = '#FFFFFF';
    context.fillRect(0, 0, canvas.width, canvas.height);

    // Render at the target resolution (DPI)
    await page.render({ canvasContext: context, viewport: rasterViewport } as any).promise;

    // Convert to JPEG with quality setting
    const imgData = canvas.toDataURL('image/jpeg', options.quality);

    // 4. Add page to new PDF
    // We use the ORIGINAL width/height for the page size so the document prints at the correct physical size.
    // But we place the (potentially downsampled) image into that box.
    const isLandscape = originalViewport.width > originalViewport.height;
    newPdf.addPage(
        [originalViewport.width, originalViewport.height], 
        isLandscape ? 'l' : 'p'
    );

    // The image data (imgData) might be small (Screen) or large (Print), 
    // but we force it to stretch to cover the physical page size.
    newPdf.addImage(
        imgData, 
        'JPEG', 
        0, 
        0, 
        originalViewport.width, 
        originalViewport.height
    );
  }

  return newPdf.output('blob');
};

