// @ts-ignore
import * as pdfjsLibProxy from 'pdfjs-dist';
// @ts-ignore
import { jsPDF } from 'jspdf';

// Handle ES module interoperability for pdfjs-dist.
// In some environments/versions, the library is exported as 'default'.
const pdfjsLib = (pdfjsLibProxy as any).default || pdfjsLibProxy;

// Singleton promise to ensure worker is initialized only once
let workerInitPromise: Promise<void> | null = null;

const initPdfWorker = () => {
  if (workerInitPromise) return workerInitPromise;

  workerInitPromise = (async () => {
    if (pdfjsLib.GlobalWorkerOptions) {
      // Use a Blob URL for the worker to avoid cross-origin restrictions (CORS) 
      // that often block 'importScripts' in Web Workers when loaded from CDNs.
      const workerUrl = 'https://unpkg.com/pdfjs-dist@3.11.174/build/pdf.worker.min.js';

      try {
        const response = await fetch(workerUrl);
        if (!response.ok) throw new Error(`Failed to fetch PDF worker: ${response.statusText}`);
        const workerScript = await response.text();
        const blob = new Blob([workerScript], { type: 'text/javascript' });
        pdfjsLib.GlobalWorkerOptions.workerSrc = URL.createObjectURL(blob);
      } catch (error) {
        console.warn("Failed to create PDF worker blob, falling back to CDN URL.", error);
        // Fallback: This might fail with "NetworkError" in some browsers if strict CORS applies to workers
        pdfjsLib.GlobalWorkerOptions.workerSrc = workerUrl;
      }
    }
  })();

  return workerInitPromise;
};

