            )}
          </div>
        </section>
      </div>

      <div className="p-6 border-t border-slate-800 bg-slate-900 sticky bottom-0 z-10">
        <button
          onClick={onProcess}
          disabled={disabled || !hasFiles || isProcessing}
          className={`w-full py-3.5 px-4 rounded-xl flex items-center justify-center gap-2 font-bold transition-all shadow-lg ${
            isProcessing
              ? 'bg-slate-700 text-slate-400 cursor-not-allowed'
              : !hasFiles
              ? 'bg-slate-800 text-slate-500 cursor-not-allowed'
              : showReprocess
              ? 'bg-gradient-to-r from-emerald-600 to-teal-600 hover:from-emerald-500 hover:to-teal-500 text-white shadow-emerald-500/20 active:scale-[0.98]'
              : 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white shadow-blue-500/20 active:scale-[0.98]'
          }`}
        >
          {isProcessing ? (
             <Activity className="w-5 h-5 animate-spin" />
          ) : showReprocess ? (
             <RotateCcw className="w-5 h-5" />
          ) : (
             <Activity className="w-5 h-5" />
          )}
          {isProcessing ? 'Processing...' : showReprocess ? 'Re-process Images' : 'Process Images'}
        </button>
      </div>
    </div>
  );
};

export default SettingsPanel;

import React, { useState, useCallback, useEffect } from 'react';
import { Layers, Download, Trash2, Loader2, Image as ImageIcon, CheckCircle2, TrendingDown } from 'lucide-react';
import SettingsPanel from './components/SettingsPanel';
import Dropzone from './components/Dropzone';
import ImageItem from './components/ImageItem';
import { ProcessingOptions, ImageItem as ImageItemType } from './types';
import { DEFAULT_OPTIONS } from './constants';
import { generateId, processFile, isHeic, convertHeicToJpeg } from './utils/imageUtils';
// @ts-ignore
import JSZip from 'jszip';

const App: React.FC = () => {
  const [files, setFiles] = useState<ImageItemType[]>([]);
  const [options, setOptions] = useState<ProcessingOptions>(DEFAULT_OPTIONS);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isZipping, setIsZipping] = useState(false);
  const [uploadProgress, setUploadProgress] = useState<{ current: number; total: number } | null>(null);

  // Clean up object URLs to prevent memory leaks
  useEffect(() => {
    return () => {
      files.forEach((file) => {
        URL.revokeObjectURL(file.previewUrl);
        if (file.processedUrl) URL.revokeObjectURL(file.processedUrl);
      });
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); 

  const handleFilesDropped = useCallback(async (newFiles: File[]) => {
    setUploadProgress({ current: 0, total: newFiles.length });
    let processedCount = 0;

    // Process one by one to avoid blocking and update UI incrementally
    for (const file of newFiles) {
      try {
          let fileToProcess = file;
          let previewUrl = '';
          let width = 0;
          let height = 0;

          // Image Handling
          if (isHeic(file)) {
            try {
                fileToProcess = await convertHeicToJpeg(file);
                previewUrl = URL.createObjectURL(fileToProcess);
            } catch (e) {
                console.error(`Failed to convert HEIC file: ${file.name}`, e);
                continue; 
            }
          } else {
            previewUrl = URL.createObjectURL(fileToProcess);
          }

          // Get dimensions
          try {
            const img = await new Promise<HTMLImageElement>((resolve, reject) => {
                const i = new Image();
                i.onload = () => resolve(i);
                i.onerror = reject;
                i.src = previewUrl;
            });
            width = img.naturalWidth;
            height = img.naturalHeight;
          } catch (e) {
              // If image fails to load, we might still process it blindly, 
              // but previewUrl is likely bad.
              console.warn("Failed to load image for dimensions", e);
          }

          const newItem: ImageItemType = {
            id: generateId(),
            file: fileToProcess,
            previewUrl,
            originalSize: file.size,
            originalWidth: width,
            originalHeight: height,
            status: 'idle',
          };

          setFiles((prev) => [...prev, newItem]);

      } catch (err) {
          console.error("Error processing dropped file", err);
      } finally {
        processedCount++;
        setUploadProgress({ current: processedCount, total: newFiles.length });
      }
    }

    setTimeout(() => {
        setUploadProgress(null);
    }, 500);
  }, []);

  const handleRemoveFile = useCallback((id: string) => {
    setFiles((prev) => {
      const fileToRemove = prev.find((f) => f.id === id);
      if (fileToRemove) {
        URL.revokeObjectURL(fileToRemove.previewUrl);
        if (fileToRemove.processedUrl) URL.revokeObjectURL(fileToRemove.processedUrl);
      }
      return prev.filter((f) => f.id !== id);
    });
  }, []);

  const handleClearAll = useCallback(() => {
    files.forEach((f) => {
      URL.revokeObjectURL(f.previewUrl);
      if (f.processedUrl) URL.revokeObjectURL(f.processedUrl);
    });
    setFiles([]);
  }, [files]);

  const handleProcessAll = useCallback(async () => {
    setIsProcessing(true);

    // Default: process only idle or error files
    let itemsToProcess = files.filter(f => f.status === 'idle' || f.status === 'error');

    // If there are no idle/error files but we have files, it means the user wants to Re-process everything
    // (e.g. they changed settings after a batch was completed)
    if (itemsToProcess.length === 0 && files.length > 0) {
        itemsToProcess = files;
    }

    for (const item of itemsToProcess) {
      setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing', error: undefined } : f));

      let result: Partial<ImageItemType>;

      try {
         result = await processFile(item, options);
      } catch (err: any) {
         result = { status: 'error', error: err.message || 'Processing failed' };
      }

      setFiles(prev => {
          const fileExists = prev.some(f => f.id === item.id);
          if (!fileExists) {
              if (result.processedUrl) URL.revokeObjectURL(result.processedUrl);
              return prev;
          }

          return prev.map(f => {
            if (f.id === item.id) {
                if (f.processedUrl && f.processedUrl !== result.processedUrl) {
                    URL.revokeObjectURL(f.processedUrl);
                }
                return { ...f, ...result };
            }
            return f;
          });
      });
    }

    setIsProcessing(false);
  }, [files, options]);

  const handleDownloadAll = useCallback(async () => {
    setIsZipping(true);
    try {
        const zip = new JSZip();

        const processedFiles = files.filter(f => f.status === 'completed' && f.processedUrl);

        if (processedFiles.length === 0) {
            setIsZipping(false);
            return;
        }

        const usedNames: Record<string, number> = {};

        for (const file of processedFiles) {
             if (!file.processedUrl) continue;

             try {
                const response = await fetch(file.processedUrl);
                const blob = await response.blob();

                let ext = 'jpg'; // default
                if (blob.type === 'image/png') {
                    ext = 'png';
                } else if (blob.type === 'image/webp') {
                    ext = 'webp';
                }

                let baseName = file.file.name.substring(0, file.file.name.lastIndexOf('.')) || file.file.name;
                // Add suffix
                let fileName = `${baseName}_optimized.${ext}`;

                if (usedNames[fileName]) {
                    usedNames[fileName]++;
                    fileName = `${baseName}_optimized_${usedNames[fileName]}.${ext}`;
                } else {
                    usedNames[fileName] = 1;
                }

                zip.file(fileName, blob);
             } catch (e) {
                 console.error(`Failed to add file ${file.file.name} to zip`, e);
             }
        }

        const content = await zip.generateAsync({ type: "blob" });
        const url = URL.createObjectURL(content);
        const link = document.createElement('a');
        link.href = url;
        link.download = "OptiBatch.zip";
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);

    } catch (error) {
        console.error("Zip failed", error);
        alert("Failed to create zip file.");
    } finally {
        setIsZipping(false);
    }
  }, [files]);

  const stats = {
    total: files.length,
    completed: files.filter(f => f.status === 'completed').length,
    savedBytes: files.reduce((acc, curr) => {
        if (curr.status === 'completed' && curr.processedSize) {
            return acc + (curr.originalSize - curr.processedSize);
        }
        return acc;
    }, 0)
  };

  const hasIdleOrError = files.some(f => f.status === 'idle' || f.status === 'error');
  const showReprocess = files.length > 0 && !hasIdleOrError;

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden relative">

      {/* Sidebar Options */}
      <SettingsPanel
        options={options}
        onOptionsChange={setOptions}
        disabled={isProcessing || files.length === 0}
        onProcess={handleProcessAll}
        isProcessing={isProcessing}
        hasFiles={files.length > 0}
        showReprocess={showReprocess}
      />

      {/* Main Content */}
      <div className="flex-1 flex flex-col min-w-0 h-full">
        {/* Header */}
        <header className="flex items-center justify-between px-8 py-4 border-b border-slate-800 bg-slate-950/50 backdrop-blur-sm z-10">
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-3">
                <div className="p-2 bg-blue-600 rounded-lg shadow-lg shadow-blue-500/20">
                <Layers className="w-6 h-6 text-white" />
                </div>
                <div>
                <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
                    OptiBatch
                </h1>
                <p className="text-xs text-slate-500 font-medium">Bulk Processor</p>
                </div>
            </div>
          </div>

          <div className="flex items-center gap-4">
             {/* Stats Indicators */}
             {files.length > 0 && (
                <div className="hidden md:flex items-center gap-3 text-xs font-medium text-slate-400 mr-2 animate-in fade-in slide-in-from-top-4 duration-300">
                    <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-800/50 border border-slate-700/50 rounded-lg shadow-sm backdrop-blur-sm">
                        <ImageIcon className="w-3.5 h-3.5 text-blue-400" />
                        <span>Files: <span className="text-white font-bold ml-0.5">{stats.total}</span></span>
                    </div>

                    {stats.completed > 0 && (
                        <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-800/50 border border-slate-700/50 rounded-lg shadow-sm backdrop-blur-sm">
                            <CheckCircle2 className="w-3.5 h-3.5 text-green-400" />
                            <span>Done: <span className="text-white font-bold ml-0.5">{stats.completed}</span></span>
                        </div>
                    )}

                    {stats.savedBytes > 0 && (
                         <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-800/50 border border-slate-700/50 rounded-lg shadow-sm backdrop-blur-sm">
                            <TrendingDown className="w-3.5 h-3.5 text-emerald-400" />
                            <span>Saved: <span className="text-emerald-400 font-bold ml-0.5">{(stats.savedBytes / 1024 / 1024).toFixed(1)} MB</span></span>
                        </div>
                    )}
                </div>
             )}

            {stats.completed > 0 && (
                <button
                onClick={handleDownloadAll}
                disabled={isZipping || isProcessing}
                className="flex items-center gap-2 px-4 py-2 rounded-lg bg-slate-800 hover:bg-slate-700 text-blue-400 border border-slate-700 hover:border-slate-600 transition-all text-sm font-medium disabled:opacity-70 disabled:cursor-not-allowed"
                >
                {isZipping ? <Loader2 className="w-4 h-4 animate-spin" /> : <Download className="w-4 h-4" />}
                {isZipping ? 'Zipping...' : 'Download All'}
                </button>
            )}

            {files.length > 0 && (
                <button
                onClick={handleClearAll}
                disabled={isProcessing || isZipping}
                className="flex items-center gap-2 px-4 py-2 rounded-lg text-slate-400 hover:text-red-400 hover:bg-red-500/10 transition-all text-sm font-medium disabled:opacity-50"
                >
                <Trash2 className="w-4 h-4" />
                Clear
                </button>
            )}
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto custom-scrollbar p-8">
          {files.length === 0 ? (
            <div className="h-full flex flex-col justify-center max-w-2xl mx-auto">
              <Dropzone onFilesDropped={handleFilesDropped} />

              <div className="mt-12 grid grid-cols-3 gap-6">
                 <div className="p-4 rounded-xl bg-slate-900 border border-slate-800">
                    <div className="w-8 h-8 rounded-lg bg-blue-500/10 flex items-center justify-center mb-3">
                        <span className="text-blue-400 font-bold text-lg">1</span>
                    </div>
                    <h3 className="font-medium text-slate-200 mb-1">Upload</h3>
                    <p className="text-xs text-slate-500">Drag & drop multiple images.</p>
                 </div>
                 <div className="p-4 rounded-xl bg-slate-900 border border-slate-800">
                    <div className="w-8 h-8 rounded-lg bg-purple-500/10 flex items-center justify-center mb-3">
                        <span className="text-purple-400 font-bold text-lg">2</span>
                    </div>
                    <h3 className="font-medium text-slate-200 mb-1">Configure</h3>
                    <p className="text-xs text-slate-500">
                        Set size, format and quality.
                    </p>
                 </div>
                 <div className="p-4 rounded-xl bg-slate-900 border border-slate-800">
                    <div className="w-8 h-8 rounded-lg bg-green-500/10 flex items-center justify-center mb-3">
                        <span className="text-green-400 font-bold text-lg">3</span>
                    </div>
                    <h3 className="font-medium text-slate-200 mb-1">Process</h3>
                    <p className="text-xs text-slate-500">Click process and download your optimized files.</p>
                 </div>
              </div>
            </div>
          ) : (
            <div className="max-w-4xl mx-auto space-y-4 pb-20">
               <div className="flex justify-end mb-4">
                  <Dropzone 
                    onFilesDropped={handleFilesDropped} 
                    isCompact 
                    className="w-full h-24"
                  />
               </div>

               <div className="space-y-3">
                {files.map((file) => (
                    <ImageItem
                    key={file.id}
                    item={file}
                    onRemove={handleRemoveFile}
                    />
                ))}
               </div>
            </div>
          )}
        </div>
      </div>

      {uploadProgress && (
        <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-50 bg-slate-900/95 border border-slate-700 p-4 rounded-xl shadow-2xl flex items-center gap-4 min-w-[320px] backdrop-blur-md animate-in slide-in-from-bottom-4 duration-300">
            <Loader2 className="w-5 h-5 text-blue-500 animate-spin shrink-0" />
            <div className="flex-1 min-w-0">
                <div className="flex justify-between text-xs font-medium mb-1.5">
                    <span className="text-slate-200">Processing inputs...</span>
                    <span className="text-slate-400 font-mono">{uploadProgress.current} / {uploadProgress.total}</span>
                </div>
                <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden">
                    <div 
                        className="h-full bg-blue-500 transition-all duration-300 ease-out rounded-full"
                        style={{ width: `${(uploadProgress.current / uploadProgress.total) * 100}%` }}
                    />
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default App;

export type ImageFormat = 'image/jpeg' | 'image/png' | 'image/webp';

export type ResizeMode = 'original' | 'percentage' | 'fixed-width' | 'fixed-height';

export interface ProcessingOptions {
  format: ImageFormat;
  quality: number; // 0.1 to 1.0
  resizeMode: ResizeMode;
  resizeValue: number; // Percentage (1-100) or pixels
  maintainAspectRatio: boolean;
}

export type ProcessStatus = 'idle' | 'processing' | 'completed' | 'error';

export interface ImageItem {
  id: string;
  file: File;
  previewUrl: string;
  originalSize: number;
  originalWidth: number;
  originalHeight: number;
  status: ProcessStatus;
  processedUrl?: string;
  processedFormat?: ImageFormat;
  processedSize?: number;
  processedWidth?: number;
  processedHeight?: number;
  error?: string;
}

import { ProcessingOptions, ImageItem } from '../types';
// @ts-ignore
import heic2any from 'heic2any';

export const formatBytes = (bytes: number, decimals = 1): string => {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const dm = decimals < 0 ? 0 : decimals;
  const sizes = ['B', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + ' ' + sizes[i];
};

export const generateId = (): string => {
  return Math.random().toString(36).substring(2, 9);
};

export const loadImage = (url: string): Promise<HTMLImageElement> => {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = 'anonymous';
    img.onload = () => resolve(img);
    img.onerror = () => reject(new Error('Failed to load image'));
    img.src = url;
  });
};

export const isHeic = (file: File): boolean => {
  return file.type.toLowerCase() === 'image/heic' || 
         file.type.toLowerCase() === 'image/heif' ||
         file.name.toLowerCase().endsWith('.heic') ||
         file.name.toLowerCase().endsWith('.heif');
};

export const convertHeicToJpeg = async (file: File): Promise<File> => {
  try {
    const result = await heic2any({
      blob: file,
      toType: 'image/jpeg',
      quality: 0.9
    });

    // Handle case where it returns Blob[] (multiframe heic), just take first
    const finalBlob = Array.isArray(result) ? result[0] : result;

    // Create a new File object to keep the name but change extension
    const newName = file.name.replace(/\.(heic|heif)$/i, '.jpg');
    return new File([finalBlob], newName, { type: 'image/jpeg' });
  } catch (error) {
    console.error("HEIC conversion failed", error);
    throw error;
  }
};

export const processFile = async (
  item: ImageItem,
  options: ProcessingOptions
): Promise<Partial<ImageItem>> => {
  try {
    // Standard Image Processing
    const img = await loadImage(item.previewUrl);

    let targetWidth = img.naturalWidth;
    let targetHeight = img.naturalHeight;

    // Calculate dimensions
    if (options.resizeMode === 'percentage') {
      const ratio = options.resizeValue / 100;
      targetWidth = Math.round(targetWidth * ratio);
      targetHeight = Math.round(targetHeight * ratio);
    } else if (options.resizeMode === 'fixed-width') {
      targetWidth = options.resizeValue;
      if (options.maintainAspectRatio) {
        const ratio = img.naturalHeight / img.naturalWidth;
        targetHeight = Math.round(targetWidth * ratio);
      }
    } else if (options.resizeMode === 'fixed-height') {
      targetHeight = options.resizeValue;
      if (options.maintainAspectRatio) {
        const ratio = img.naturalWidth / img.naturalHeight;
        targetWidth = Math.round(targetHeight * ratio);
      }
    }

    // Create canvas
    const canvas = document.createElement('canvas');
    canvas.width = targetWidth;
    canvas.height = targetHeight;
    const ctx = canvas.getContext('2d');

    if (!ctx) {
      throw new Error('Could not get canvas context');
    }

    // Better quality scaling
    ctx.imageSmoothingEnabled = true;
    ctx.imageSmoothingQuality = 'high';
    ctx.drawImage(img, 0, 0, targetWidth, targetHeight);

    // Convert to blob
    const blob = await new Promise<Blob | null>((resolve) => {
      canvas.toBlob(
        (b) => resolve(b),
        options.format,
        options.quality
      );
    });

    if (!blob) {
      throw new Error('Image encoding failed');
    }

    const processedUrl = URL.createObjectURL(blob);

    return {
      status: 'completed',
      processedUrl,
      processedFormat: options.format,
      processedSize: blob.size,
      processedWidth: targetWidth,
      processedHeight: targetHeight,
      error: undefined,
    };
  } catch (err: any) {
    console.error("Processing error:", err);
    return {
      status: 'error',
      error: err.message || 'Processing failed',
    };
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { X, ArrowRight, Download, AlertCircle, Loader2, ScanEye, ZoomIn, MousePointer2 } from 'lucide-react';
import { ImageItem as ImageItemType } from '../types';
import { formatBytes } from '../utils/imageUtils';
import CompareModal from './CompareModal';

interface ImageItemProps {
  item: ImageItemType;
  onRemove: (id: string) => void;
}

const ImageItem: React.FC<ImageItemProps> = ({ item, onRemove }) => {
  const [showPreview, setShowPreview] = useState(false);
  const [showCompare, setShowCompare] = useState(false);
  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
  const [zoom, setZoom] = useState(1);
  const [relPos, setRelPos] = useState({ x: 50, y: 50 });
  const thumbnailRef = useRef<HTMLDivElement>(null);

  // Use native event listener for wheel to properly prevent default scroll behavior
  useEffect(() => {
    const element = thumbnailRef.current;
    if (!element) return;

    const handleWheel = (e: WheelEvent) => {
      e.preventDefault();
      // Adjust sensitivity and limits
      const delta = -e.deltaY * 0.005;
      setZoom(z => Math.min(Math.max(1, z + delta), 8));
    };

    element.addEventListener('wheel', handleWheel, { passive: false });
    return () => element.removeEventListener('wheel', handleWheel);
  }, []);

  const handleMouseEnter = (e: React.MouseEvent) => {
    setShowPreview(true);
    setCursorPos({ x: e.clientX, y: e.clientY });
    updateRelPos(e);
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    setCursorPos({ x: e.clientX, y: e.clientY });
    updateRelPos(e);
  };

  const handleMouseLeave = () => {
    setShowPreview(false);
    setZoom(1);
  };

  const updateRelPos = (e: React.MouseEvent) => {
    if (thumbnailRef.current) {
        const rect = thumbnailRef.current.getBoundingClientRect();
        // Calculate percentage position within the thumbnail
        const x = Math.max(0, Math.min(100, ((e.clientX - rect.left) / rect.width) * 100));
        const y = Math.max(0, Math.min(100, ((e.clientY - rect.top) / rect.height) * 100));
        setRelPos({ x, y });
    }
  };

  // Determine if preview should show on left or right to avoid clipping
  const isRightHalf = typeof window !== 'undefined' && cursorPos.x > window.innerWidth / 2;

  const getExtension = (format: string) => {
    if (format === 'image/png') return 'png';
    if (format === 'image/webp') return 'webp';
    return 'jpg';
  };

  const baseName = item.file.name.substring(0, item.file.name.lastIndexOf('.')) || item.file.name;
  const downloadName = item.processedFormat 
    ? `${baseName}_optimized.${getExtension(item.processedFormat)}`
    : item.file.name;

  return (
    <>
      {showCompare && item.processedUrl && (
        <CompareModal
          originalUrl={item.previewUrl}
          processedUrl={item.processedUrl}
          fileName={item.file.name}
          onClose={() => setShowCompare(false)}
        />
      )}

      {showPreview && !showCompare && (
        <div 
          className="fixed z-[100] pointer-events-none p-2 bg-slate-900/95 border border-slate-700 rounded-xl shadow-2xl backdrop-blur-sm transition-opacity duration-200"
          style={{
            top: cursorPos.y,
            left: isRightHalf ? cursorPos.x - 24 : cursorPos.x + 24,
            transform: `translate(${isRightHalf ? '-100%' : '0'}, -50%)`,
            width: '400px',
            maxWidth: '90vw',
          }}
        >
          {/* Preview Image Container */}
          <div className="relative w-full aspect-square bg-slate-950/50 rounded-lg overflow-hidden border border-slate-800">
             <img 
                src={item.previewUrl} 
                alt="Preview" 
                className="w-full h-full object-contain transition-transform duration-75 ease-out origin-center"
                style={{
                    transform: `scale(${zoom})`,
                    transformOrigin: `${relPos.x}% ${relPos.y}%`
                }}
             />

             {/* Zoom Badge */}
             {zoom > 1 && (
                 <div className="absolute top-3 right-3 z-10 bg-black/70 backdrop-blur-md text-white text-[10px] font-mono px-2 py-1 rounded-full border border-white/10 flex items-center gap-1 shadow-lg">
                    <ZoomIn className="w-3 h-3 text-blue-400" />
                    {zoom.toFixed(1)}x
                 </div>
             )}
          </div>

          <div className="mt-2 flex justify-between items-center px-1 border-t border-slate-800 pt-2">
             <div className="flex flex-col">
                <span className="text-[10px] text-slate-500 font-medium uppercase tracking-wider">Original</span>
                <span className="text-xs text-slate-300 font-mono">
                    {item.originalWidth} × {item.originalHeight}
                </span>
             </div>
             <div className="flex flex-col items-end">
                {zoom === 1 ? (
                    <div className="flex items-center gap-1 text-[10px] text-slate-500">
                        <MousePointer2 className="w-3 h-3" />
                        <span>Scroll to zoom</span>
                    </div>
                ) : (
                    <div className="flex flex-col items-end">
                        <span className="text-[10px] text-slate-500 font-medium uppercase tracking-wider">Size</span>
                        <span className="text-xs text-slate-300 font-mono">{formatBytes(item.originalSize)}</span>
                    </div>
                )}
             </div>
          </div>
        </div>
      )}

      <div className="group flex items-center gap-4 bg-slate-900 border border-slate-800 p-3 rounded-xl hover:border-slate-700 transition-all">
        {/* Thumbnail */}
        <div 
          ref={thumbnailRef}
          className="relative w-16 h-16 shrink-0 rounded-lg overflow-hidden bg-slate-800 border border-slate-700 cursor-crosshair"
          onMouseEnter={handleMouseEnter}
          onMouseMove={handleMouseMove}
          onMouseLeave={handleMouseLeave}
        >
          <img
            src={item.previewUrl}
            alt="thumbnail"
            className="w-full h-full object-cover"
          />
          {item.status === 'processing' && (
             <div className="absolute inset-0 bg-slate-900/60 flex items-center justify-center backdrop-blur-[1px]">
                 <Loader2 className="w-6 h-6 text-blue-500 animate-spin" />
             </div>
          )}
        </div>

        {/* Details */}
        <div className="flex-1 min-w-0">
          <div className="flex items-center justify-between mb-1">
              <h4 className="text-sm font-medium text-slate-200 truncate pr-4" title={item.file.name}>
              {item.file.name}
              </h4>
              <div className="flex items-center gap-2">
                 {item.status === 'completed' && (
                    <span className="text-[10px] font-bold px-1.5 py-0.5 rounded bg-green-500/10 text-green-400 border border-green-500/20">
                        SAVED {Math.max(0, Math.round(((item.originalSize - (item.processedSize || 0)) / item.originalSize) * 100))}%
                    </span>
                 )}
              </div>
          </div>

          <div className="flex items-center gap-3 text-xs text-slate-500">
            <div className="flex items-center gap-1.5">
              <span className="bg-slate-800 px-1.5 py-0.5 rounded text-slate-400 font-mono">
                {item.originalWidth}x{item.originalHeight}
              </span>
              <span className="font-mono">{formatBytes(item.originalSize)}</span>
            </div>

            {item.status === 'completed' && (
              <>
                <ArrowRight className="w-3 h-3 text-slate-600" />
                <div className="flex items-center gap-1.5 text-blue-400">
                  <span className="bg-blue-500/10 px-1.5 py-0.5 rounded border border-blue-500/20 font-mono">
                    {item.processedWidth}x{item.processedHeight}
                  </span>
                  <span className="font-mono font-semibold">{formatBytes(item.processedSize || 0)}</span>
                </div>
              </>
            )}

           {item.status === 'error' && (
                <span className="text-red-400 flex items-center gap-1">
                    <AlertCircle className="w-3 h-3" />
                    Failed
                </span>
           )}
        </div>
      </div>

      {/* Actions */}
      <div className="flex items-center gap-2">
        {item.status === 'completed' && item.processedUrl && (
            <>
            <button
                onClick={() => setShowCompare(true)}
                className="p-2 rounded-lg text-slate-500 hover:text-blue-400 hover:bg-blue-500/10 transition-colors"
                title="Compare Original vs Processed"
            >
                <ScanEye className="w-5 h-5" />
            </button>
            <a
                href={item.processedUrl}
                download={downloadName}
                className="p-2 rounded-lg text-slate-400 hover:text-green-400 hover:bg-green-500/10 transition-colors"
                title="Download"
            >
                <Download className="w-5 h-5" />
            </a>
            </>
        )}

        <button
          onClick={() => onRemove(item.id)}
          className="p-2 rounded-lg transition-colors focus:opacity-100 text-slate-500 hover:text-red-400 hover:bg-red-500/10 opacity-0 group-hover:opacity-100"
          title="Remove"
        >
          <X className="w-5 h-5" />
        </button>
      </div>
    </div>
    </>
  );
};

export default ImageItem;

import React from 'react';
import { Settings, Sliders, Image as ImageIcon, Type, Activity, RotateCcw } from 'lucide-react';
import { ProcessingOptions, ResizeMode, ImageFormat } from '../types';
import { SUPPORTED_FORMATS } from '../constants';

interface SettingsPanelProps {
  options: ProcessingOptions;
  onOptionsChange: (newOptions: ProcessingOptions) => void;
  disabled?: boolean;
  onProcess: () => void;
  isProcessing: boolean;
  hasFiles: boolean;
  showReprocess?: boolean;
}

const SettingsPanel: React.FC<SettingsPanelProps> = ({
  options,
  onOptionsChange,
  disabled = false,
  onProcess,
  isProcessing,
  hasFiles,
  showReprocess = false,
}) => {
  const handleChange = <K extends keyof ProcessingOptions>(
    key: K,
    value: ProcessingOptions[K]
  ) => {
    if (key === 'resizeMode') {
      const newMode = value as ResizeMode;
      const updates: Partial<ProcessingOptions> = { resizeMode: newMode };

      // Set sensible defaults when switching modes
      if (newMode === 'fixed-width') {
        updates.resizeValue = 1200;
      } else if (newMode === 'fixed-height') {
        updates.resizeValue = 800;
      } else if (newMode === 'percentage') {
        updates.resizeValue = 100;
      }

      onOptionsChange({ ...options, ...updates });
    } else {
      onOptionsChange({ ...options, [key]: value });
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 border-r border-slate-800 w-80 shrink-0 overflow-y-auto custom-scrollbar">
      <div className="p-6 border-b border-slate-800">
        <h2 className="text-lg font-bold text-white flex items-center gap-2">
          <Settings className="w-5 h-5 text-blue-500" />
          Image Settings
        </h2>
        <p className="text-xs text-slate-400 mt-1">
          Adjust settings for all files
        </p>
      </div>

      <div className="p-6 space-y-8 flex-1">

        {/* === IMAGE MODE SETTINGS === */}
        <section className="space-y-4">
          <div className="flex items-center gap-2 text-sm font-medium text-slate-300">
            <ImageIcon className="w-4 h-4 text-blue-400" />
            RESIZE
          </div>

          <div className="grid grid-cols-2 gap-2">
            {(['original', 'percentage', 'fixed-width', 'fixed-height'] as ResizeMode[]).map((m) => (
              <button
                key={m}
                onClick={() => handleChange('resizeMode', m)}
                disabled={disabled}
                className={`px-3 py-2 text-xs font-medium rounded-lg border transition-all ${
                  options.resizeMode === m
                    ? 'bg-blue-600 border-blue-500 text-white'
                    : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-600'
                }`}
              >
                {m.replace('-', ' ').toUpperCase()}
              </button>
            ))}
          </div>

          {options.resizeMode !== 'original' && (
            <div className="space-y-3 p-4 bg-slate-800/50 rounded-lg border border-slate-700/50">
              <label className="text-xs text-slate-400">
                {options.resizeMode === 'percentage' ? 'Scale Percentage' : 'Target Pixels'}
              </label>
              <div className="flex items-center gap-3">
                <input
                  type="range"
                  min={options.resizeMode === 'percentage' ? 10 : 100}
                  max={options.resizeMode === 'percentage' ? 200 : 4000}
                  step={options.resizeMode === 'percentage' ? 5 : 50}
                  value={options.resizeValue}
                  disabled={disabled}
                  onChange={(e) => handleChange('resizeValue', Number(e.target.value))}
                  className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                />
                <span className="text-sm font-mono text-white min-w-[3rem] text-right">
                  {options.resizeValue}{options.resizeMode === 'percentage' ? '%' : 'px'}
                </span>
              </div>
              <label className="flex items-center gap-2 cursor-pointer group">
                  <input 
                      type="checkbox"
                      checked={options.maintainAspectRatio}
                      onChange={(e) => handleChange('maintainAspectRatio', e.target.checked)}
                      disabled={disabled}
                      className="rounded border-slate-600 bg-slate-700 text-blue-500 focus:ring-offset-slate-900"
                  />
                  <span className="text-xs text-slate-400 group-hover:text-slate-300">Maintain aspect ratio</span>
              </label>
            </div>
          )}
        </section>

        {/* Format Section */}
        <section className="space-y-4">
        <div className="flex items-center gap-2 text-sm font-medium text-slate-300">
            <Type className="w-4 h-4 text-purple-400" />
            OUTPUT FORMAT
        </div>
        <div className="grid grid-cols-1 gap-2">
            <select
            value={options.format}
            onChange={(e) => handleChange('format', e.target.value as ImageFormat)}
            disabled={disabled}
            className={`w-full px-3 py-2 bg-slate-800 border border-slate-700 rounded-lg text-sm text-white focus:outline-none focus:border-blue-500`}
            >
            {Object.entries(SUPPORTED_FORMATS).map(([value, label]) => (
                <option key={value} value={value}>
                {label}
                </option>
            ))}
            </select>
        </div>
        </section>

        {/* Quality Section - Shared */}
        <section className="space-y-4">
          <div className="flex items-center gap-2 text-sm font-medium text-slate-300">
            <Sliders className="w-4 h-4 text-green-400" />
            COMPRESSION QUALITY
          </div>

          <div className="space-y-3 p-4 bg-slate-800/50 rounded-lg border border-slate-700/50">
             <div className="flex justify-between items-center">
                 <span className="text-xs text-slate-400">Low</span>
                 <span className="text-xs text-slate-400">High</span>
             </div>
            <div className="flex items-center gap-3">
                <input
                  type="range"
                  min="0.1"
                  max="1.0"
                  step="0.05"
                  value={options.quality}
                  disabled={disabled || options.format === 'image/png'}
                  onChange={(e) => handleChange('quality', Number(e.target.value))}
                  className={`w-full h-1.5 rounded-lg appearance-none cursor-pointer accent-blue-500 ${options.format === 'image/png' ? 'bg-slate-700 opacity-50' : 'bg-slate-700'}`}
                />
                <span className="text-sm font-mono text-white min-w-[3rem] text-right">
                  {Math.round(options.quality * 100)}%
                </span>
            </div>
            {options.format === 'image/png' && (
                <p className="text-[10px] text-yellow-500/80">
                    * PNG is lossless. Quality setting may not apply.
                </p>
            )}
          </div>
        </section>
      </div>

      <div className="p-6 border-t border-slate-800 bg-slate-900 sticky bottom-0 z-10">
        <button
          onClick={onProcess}
          disabled={disabled || !hasFiles || isProcessing}
          className={`w-full py-3.5 px-4 rounded-xl flex items-center justify-center gap-2 font-bold transition-all shadow-lg ${
            isProcessing
              ? 'bg-slate-700 text-slate-400 cursor-not-allowed'
              : !hasFiles
              ? 'bg-slate-800 text-slate-500 cursor-not-allowed'
              : showReprocess
              ? 'bg-gradient-to-r from-emerald-600 to-teal-600 hover:from-emerald-500 hover:to-teal-500 text-white shadow-emerald-500/20 active:scale-[0.98]'
              : 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white shadow-blue-500/20 active:scale-[0.98]'
          }`}
        >
          {isProcessing ? (
             <Activity className="w-5 h-5 animate-spin" />
          ) : showReprocess ? (
             <RotateCcw className="w-5 h-5" />
          ) : (
             <Activity className="w-5 h-5" />
          )}
          {isProcessing ? 'Processing...' : showReprocess ? 'Re-process Images' : 'Process Images'}
        </button>
      </div>
    </div>
  );
};

export default SettingsPanel;

