};

export const PDF_COMPRESSION_LEVELS = {
  low: { label: 'Low (Faster)', quality: 0.9 },
  medium: { label: 'Medium (Balanced)', quality: 0.7 },
  high: { label: 'High (Smallest)', quality: 0.4 },
};

export const SUPPORTED_FORMATS = {
  'image/jpeg': 'JPEG',
