          {item.status === 'completed' && item.processedSize && (
            <>
              <ArrowRight className="w-3 h-3 text-slate-600" />
              <div className="flex items-center gap-1.5 text-blue-400">
                <span className="font-mono font-semibold">{formatBytes(item.processedSize)}</span>
              </div>
            </>
          )}

          {item.status === 'error' && (
            <span className="text-red-400 flex items-center gap-1">
              <AlertCircle className="w-3 h-3" />
              Failed
            </span>
          )}
        </div>
      </div>

      {/* Actions */}
      <div className="flex items-center gap-2">
        {item.status === 'completed' && item.processedUrl && (
          <a
            href={item.processedUrl}
            download={downloadName}
            className="p-2 rounded-lg text-slate-400 hover:text-green-400 hover:bg-green-500/10 transition-colors"
            title="Download"
          >
            <Download className="w-5 h-5" />
          </a>
        )}

        <button
          onClick={() => onRemove(item.id)}
          className="p-2 rounded-lg transition-colors focus:opacity-100 text-slate-500 hover:text-red-400 hover:bg-red-500/10 opacity-0 group-hover:opacity-100"
          title="Remove"
        >
          <X className="w-5 h-5" />
        </button>
      </div>
    </div>
  );
};

export default PdfItem;

import React from 'react';
import { Settings, Sliders, Image as ImageIcon, Type, Activity, RotateCcw, FileText, FileSearch } from 'lucide-react';
import { ProcessingOptions, ResizeMode, ImageFormat, AppMode, PdfProcessingOptions, PdfCompressionLevel } from '../types';
import { SUPPORTED_FORMATS, PDF_COMPRESSION_LEVELS } from '../constants';

interface SettingsPanelProps {
  mode: AppMode;
  onModeChange: (mode: AppMode) => void;
  options: ProcessingOptions;
  onOptionsChange: (newOptions: ProcessingOptions) => void;
  pdfOptions: PdfProcessingOptions;
  onPdfOptionsChange: (newOptions: PdfProcessingOptions) => void;
  disabled?: boolean;
  onProcess: () => void;
  isProcessing: boolean;
  hasFiles: boolean;
  showReprocess?: boolean;
}

const SettingsPanel: React.FC<SettingsPanelProps> = ({
  mode,
  onModeChange,
  options,
  onOptionsChange,
  pdfOptions,
  onPdfOptionsChange,
  disabled = false,
  onProcess,
  isProcessing,
  hasFiles,
  showReprocess = false,
}) => {
  const handleChange = <K extends keyof ProcessingOptions>(
    key: K,
    value: ProcessingOptions[K]
  ) => {
    if (key === 'resizeMode') {
      const newMode = value as ResizeMode;
      const updates: Partial<ProcessingOptions> = { resizeMode: newMode };

      if (newMode === 'fixed-width') {
        updates.resizeValue = 1200;
      } else if (newMode === 'fixed-height') {
        updates.resizeValue = 800;
      } else if (newMode === 'percentage') {
        updates.resizeValue = 100;
      }

      onOptionsChange({ ...options, ...updates });
    } else {
      onOptionsChange({ ...options, [key]: value });
    }
  };

  const handlePdfChange = (level: PdfCompressionLevel) => {
    onPdfOptionsChange({ compressionLevel: level });
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 border-r border-slate-800 w-80 shrink-0 overflow-y-auto custom-scrollbar">
      {/* Tab Switcher */}
      <div className="p-4 bg-slate-950/50 border-b border-slate-800">
        <div className="flex bg-slate-900 p-1 rounded-xl border border-slate-800">
            <button 
                onClick={() => onModeChange('image')}
                className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-bold transition-all ${mode === 'image' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
            >
                <ImageIcon className="w-4 h-4" />
                Images
            </button>
            <button 
                onClick={() => onModeChange('pdf')}
                className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-bold transition-all ${mode === 'pdf' ? 'bg-red-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
            >
                <FileText className="w-4 h-4" />
                PDFs
            </button>
        </div>
      </div>

      <div className="p-6 border-b border-slate-800">
        <h2 className="text-lg font-bold text-white flex items-center gap-2">
          <Settings className={`w-5 h-5 ${mode === 'image' ? 'text-blue-500' : 'text-red-500'}`} />
          {mode === 'image' ? 'Image Settings' : 'PDF Settings'}
        </h2>
        <p className="text-xs text-slate-400 mt-1">
          Adjust settings for all {mode === 'image' ? 'images' : 'PDFs'}
        </p>
      </div>

      <div className="p-6 space-y-8 flex-1">
        {mode === 'image' ? (
          <>
            <section className="space-y-4">
              <div className="flex items-center gap-2 text-sm font-medium text-slate-300">
                <ImageIcon className="w-4 h-4 text-blue-400" />
                RESIZE
              </div>
              <div className="grid grid-cols-2 gap-2">
                {(['original', 'percentage', 'fixed-width', 'fixed-height'] as ResizeMode[]).map((m) => (
                  <button
                    key={m}
                    onClick={() => handleChange('resizeMode', m)}
                    disabled={disabled}
                    className={`px-3 py-2 text-xs font-medium rounded-lg border transition-all ${
                      options.resizeMode === m
                        ? 'bg-blue-600 border-blue-500 text-white'
                        : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-600'
                    }`}
                  >
                    {m.replace('-', ' ').toUpperCase()}
                  </button>
                ))}
              </div>
              {options.resizeMode !== 'original' && (
                <div className="space-y-3 p-4 bg-slate-800/50 rounded-lg border border-slate-700/50">
                  <label className="text-xs text-slate-400">
                    {options.resizeMode === 'percentage' ? 'Scale Percentage' : 'Target Pixels'}
                  </label>
                  <div className="flex items-center gap-3">
                    <input
                      type="range"
                      min={options.resizeMode === 'percentage' ? 10 : 100}
                      max={options.resizeMode === 'percentage' ? 200 : 4000}
                      step={options.resizeMode === 'percentage' ? 5 : 50}
                      value={options.resizeValue}
                      disabled={disabled}
                      onChange={(e) => handleChange('resizeValue', Number(e.target.value))}
                      className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
                    />
                    <span className="text-sm font-mono text-white min-w-[3rem] text-right">
                      {options.resizeValue}{options.resizeMode === 'percentage' ? '%' : 'px'}
                    </span>
                  </div>
                  <label className="flex items-center gap-2 cursor-pointer group">
                      <input 
                          type="checkbox"
                          checked={options.maintainAspectRatio}
                          onChange={(e) => handleChange('maintainAspectRatio', e.target.checked)}
                          disabled={disabled}
                          className="rounded border-slate-600 bg-slate-700 text-blue-500 focus:ring-offset-slate-900"
                      />
                      <span className="text-xs text-slate-400 group-hover:text-slate-300">Maintain aspect ratio</span>
                  </label>
                </div>
              )}
            </section>

            <section className="space-y-4">
              <div className="flex items-center gap-2 text-sm font-medium text-slate-300">
                  <Type className="w-4 h-4 text-purple-400" />
                  OUTPUT FORMAT
              </div>
              <select
                value={options.format}
                onChange={(e) => handleChange('format', e.target.value as ImageFormat)}
                disabled={disabled}
                className="w-full px-3 py-2 bg-slate-800 border border-slate-700 rounded-lg text-sm text-white focus:outline-none focus:border-blue-500"
              >
                {Object.entries(SUPPORTED_FORMATS).map(([value, label]) => (
                    <option key={value} value={value}>{label}</option>
                ))}
              </select>
            </section>

            <section className="space-y-4">
              <div className="flex items-center gap-2 text-sm font-medium text-slate-300">
                <Sliders className="w-4 h-4 text-green-400" />
                COMPRESSION QUALITY
              </div>
              <div className="space-y-3 p-4 bg-slate-800/50 rounded-lg border border-slate-700/50">
                <div className="flex justify-between items-center text-xs text-slate-500">
                  <span>Smallest</span>
                  <span>Highest Quality</span>
                </div>
                <div className="flex items-center gap-3">
                    <input
                      type="range"
                      min="0.1"
                      max="1.0"
                      step="0.05"
                      value={options.quality}
                      disabled={disabled || options.format === 'image/png'}
                      onChange={(e) => handleChange('quality', Number(e.target.value))}
                      className={`w-full h-1.5 rounded-lg appearance-none cursor-pointer accent-blue-500 ${options.format === 'image/png' ? 'bg-slate-700 opacity-50' : 'bg-slate-700'}`}
                    />
                    <span className="text-sm font-mono text-white min-w-[3rem] text-right">
                      {Math.round(options.quality * 100)}%
                    </span>
                </div>
              </div>
            </section>
          </>
        ) : (
          <section className="space-y-6">
            <div className="flex items-center gap-2 text-sm font-medium text-slate-300">
              <FileSearch className="w-4 h-4 text-red-400" />
              COMPRESSION LEVEL
            </div>

            <div className="space-y-2">
              {(Object.keys(PDF_COMPRESSION_LEVELS) as PdfCompressionLevel[]).map((level) => (
                <button
                  key={level}
                  onClick={() => handlePdfChange(level)}
                  className={`w-full p-4 rounded-xl border text-left transition-all ${
                    pdfOptions.compressionLevel === level
                      ? 'bg-red-500/10 border-red-500 text-red-100'
                      : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-600'
                  }`}
                >
                  <div className="text-sm font-bold mb-0.5">{PDF_COMPRESSION_LEVELS[level].label}</div>
                  <div className="text-[10px] opacity-70">
                    {level === 'low' && 'Best for text-only documents.'}
                    {level === 'medium' && 'Good balance for documents with images.'}
                    {level === 'high' && 'Aggressive optimization for smallest size.'}
                  </div>
                </button>
              ))}
            </div>

            <div className="p-4 bg-amber-500/10 border border-amber-500/20 rounded-lg">
                <p className="text-[10px] text-amber-500 leading-relaxed">
                    PDF optimization processes the document structure to reduce size while preserving readability.
                </p>
            </div>
          </section>
        )}
      </div>

      <div className="p-6 border-t border-slate-800 bg-slate-900 sticky bottom-0 z-10">
        <button
          onClick={onProcess}
          disabled={disabled || !hasFiles || isProcessing}
          className={`w-full py-3.5 px-4 rounded-xl flex items-center justify-center gap-2 font-bold transition-all shadow-lg ${
            isProcessing
              ? 'bg-slate-700 text-slate-400 cursor-not-allowed'
              : !hasFiles
              ? 'bg-slate-800 text-slate-500 cursor-not-allowed'
              : mode === 'image' 
                ? (showReprocess ? 'bg-gradient-to-r from-emerald-600 to-teal-600 hover:from-emerald-500 hover:to-teal-500' : 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500')
                : (showReprocess ? 'bg-gradient-to-r from-emerald-600 to-teal-600 hover:from-emerald-500 hover:to-teal-500' : 'bg-gradient-to-r from-red-600 to-orange-600 hover:from-red-500 hover:to-orange-500')
          } text-white shadow-lg active:scale-[0.98]`}
        >
          {isProcessing ? <Activity className="w-5 h-5 animate-spin" /> : showReprocess ? <RotateCcw className="w-5 h-5" /> : <Activity className="w-5 h-5" />}
          {isProcessing ? 'Processing...' : showReprocess ? 'Re-process' : (mode === 'image' ? 'Process Images' : 'Optimize PDFs')}
        </button>
      </div>
    </div>
  );
};

export default SettingsPanel;

import React, { useState, useCallback, useEffect } from 'react';
import { Layers, Download, Trash2, Loader2, Image as ImageIcon, CheckCircle2, TrendingDown, FileText } from 'lucide-react';
import SettingsPanel from './components/SettingsPanel';
import Dropzone from './components/Dropzone';
import ImageItem from './components/ImageItem';
import PdfItem from './components/PdfItem';
import { ProcessingOptions, ImageItem as ImageItemType, AppMode, PdfItem as PdfItemType, PdfProcessingOptions } from './types';
import { DEFAULT_OPTIONS, DEFAULT_PDF_OPTIONS } from './constants';
import { generateId, processFile, isHeic, convertHeicToJpeg } from './utils/imageUtils';
import { processPdf } from './utils/pdfUtils';
// @ts-ignore
import JSZip from 'jszip';

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>('image');

  // Image State
  const [files, setFiles] = useState<ImageItemType[]>([]);
  const [options, setOptions] = useState<ProcessingOptions>(DEFAULT_OPTIONS);

  // PDF State
  const [pdfFiles, setPdfFiles] = useState<PdfItemType[]>([]);
  const [pdfOptions, setPdfOptions] = useState<PdfProcessingOptions>(DEFAULT_PDF_OPTIONS);

  const [isProcessing, setIsProcessing] = useState(false);
  const [isZipping, setIsZipping] = useState(false);
  const [uploadProgress, setUploadProgress] = useState<{ current: number; total: number } | null>(null);

  // Clean up object URLs
  useEffect(() => {
    return () => {
      files.forEach((file) => {
        URL.revokeObjectURL(file.previewUrl);
        if (file.processedUrl) URL.revokeObjectURL(file.processedUrl);
      });
      pdfFiles.forEach((file) => {
        if (file.processedUrl) URL.revokeObjectURL(file.processedUrl);
      });
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); 

  const handleFilesDropped = useCallback(async (newFiles: File[]) => {
    setUploadProgress({ current: 0, total: newFiles.length });
    let processedCount = 0;

    for (const file of newFiles) {
      try {
          if (mode === 'image') {
              let fileToProcess = file;
              let previewUrl = '';
              let width = 0;
              let height = 0;

              if (isHeic(file)) {
                try {
                    fileToProcess = await convertHeicToJpeg(file);
                    previewUrl = URL.createObjectURL(fileToProcess);
                } catch (e) {
                    console.error(`Failed to convert HEIC file: ${file.name}`, e);
                    continue; 
                }
              } else {
                previewUrl = URL.createObjectURL(fileToProcess);
              }

              try {
                const img = await new Promise<HTMLImageElement>((resolve, reject) => {
                    const i = new Image();
                    i.onload = () => resolve(i);
                    i.onerror = reject;
                    i.src = previewUrl;
                });
                width = img.naturalWidth;
                height = img.naturalHeight;
              } catch (e) {
                  console.warn("Failed to load image for dimensions", e);
              }

              const newItem: ImageItemType = {
                id: generateId(),
                file: fileToProcess,
                previewUrl,
                originalSize: file.size,
                originalWidth: width,
                originalHeight: height,
                status: 'idle',
              };
              setFiles((prev) => [...prev, newItem]);
          } else {
              // PDF Handling
              const newItem: PdfItemType = {
                id: generateId(),
                file: file,
                originalSize: file.size,
                status: 'idle',
              };
              setPdfFiles((prev) => [...prev, newItem]);
          }
      } catch (err) {
          console.error("Error processing dropped file", err);
      } finally {
        processedCount++;
        setUploadProgress({ current: processedCount, total: newFiles.length });
      }
    }
    setTimeout(() => setUploadProgress(null), 500);
  }, [mode]);

  const handleRemoveFile = useCallback((id: string) => {
    if (mode === 'image') {
        setFiles((prev) => {
            const fileToRemove = prev.find((f) => f.id === id);
            if (fileToRemove) {
                URL.revokeObjectURL(fileToRemove.previewUrl);
                if (fileToRemove.processedUrl) URL.revokeObjectURL(fileToRemove.processedUrl);
            }
            return prev.filter((f) => f.id !== id);
        });
    } else {
        setPdfFiles((prev) => {
            const fileToRemove = prev.find((f) => f.id === id);
            if (fileToRemove?.processedUrl) URL.revokeObjectURL(fileToRemove.processedUrl);
            return prev.filter((f) => f.id !== id);
        });
    }
  }, [mode]);

  const handleClearAll = useCallback(() => {
    if (mode === 'image') {
        files.forEach((f) => {
            URL.revokeObjectURL(f.previewUrl);
            if (f.processedUrl) URL.revokeObjectURL(f.processedUrl);
        });
        setFiles([]);
    } else {
        pdfFiles.forEach((f) => {
            if (f.processedUrl) URL.revokeObjectURL(f.processedUrl);
        });
        setPdfFiles([]);
    }
  }, [files, pdfFiles, mode]);

  const handleProcessAll = useCallback(async () => {
    setIsProcessing(true);

    if (mode === 'image') {
        let itemsToProcess = files.filter(f => f.status === 'idle' || f.status === 'error');
        if (itemsToProcess.length === 0 && files.length > 0) itemsToProcess = files;

        for (const item of itemsToProcess) {
          setFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing', error: undefined } : f));
          let result: Partial<ImageItemType>;
          try { result = await processFile(item, options); } 
          catch (err: any) { result = { status: 'error', error: err.message || 'Processing failed' }; }

          setFiles(prev => prev.map(f => {
            if (f.id === item.id) {
                if (f.processedUrl && f.processedUrl !== result.processedUrl) URL.revokeObjectURL(f.processedUrl);
                return { ...f, ...result };
            }
            return f;
          }));
        }
    } else {
        let itemsToProcess = pdfFiles.filter(f => f.status === 'idle' || f.status === 'error');
        if (itemsToProcess.length === 0 && pdfFiles.length > 0) itemsToProcess = pdfFiles;

        for (const item of itemsToProcess) {
          setPdfFiles(prev => prev.map(f => f.id === item.id ? { ...f, status: 'processing', error: undefined } : f));
          let result: Partial<PdfItemType>;
          try { result = await processPdf(item, pdfOptions); } 
          catch (err: any) { result = { status: 'error', error: err.message || 'PDF optimization failed' }; }

          setPdfFiles(prev => prev.map(f => {
            if (f.id === item.id) {
                if (f.processedUrl && f.processedUrl !== result.processedUrl) URL.revokeObjectURL(f.processedUrl);
                return { ...f, ...result };
            }
            return f;
          }));
        }
    }

    setIsProcessing(false);
  }, [files, pdfFiles, options, pdfOptions, mode]);

  const handleDownloadAll = useCallback(async () => {
    setIsZipping(true);
    try {
        const zip = new JSZip();
        const activeFiles = mode === 'image' ? files : pdfFiles;
        const processedFiles = activeFiles.filter(f => f.status === 'completed' && f.processedUrl);

        if (processedFiles.length === 0) {
            setIsZipping(false);
            return;
        }

        const usedNames: Record<string, number> = {};

        for (const file of processedFiles) {
             if (!file.processedUrl) continue;
             try {
                const response = await fetch(file.processedUrl);
                const blob = await response.blob();

                let ext = mode === 'image' ? 'jpg' : 'pdf';
                if (blob.type === 'image/png') ext = 'png';
                else if (blob.type === 'image/webp') ext = 'webp';

                let baseName = file.file.name.substring(0, file.file.name.lastIndexOf('.')) || file.file.name;
                let fileName = `${baseName}.${ext}`;

                if (usedNames[fileName]) {
                    usedNames[fileName]++;
                    fileName = `${baseName}_${usedNames[fileName]}.${ext}`;
                } else {
                    usedNames[fileName] = 1;
                }
                zip.file(fileName, blob);
             } catch (e) {
                 console.error(`Failed to add file ${file.file.name} to zip`, e);
             }
        }

        const content = await zip.generateAsync({ type: "blob" });
        const url = URL.createObjectURL(content);
        const link = document.createElement('a');
        link.href = url;
        link.download = `OptiBatch_${mode === 'image' ? 'Images' : 'PDFs'}.zip`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
    } catch (error) {
        alert("Failed to create zip file.");
    } finally {
        setIsZipping(false);
    }
  }, [files, pdfFiles, mode]);

  const currentFiles = mode === 'image' ? files : pdfFiles;
  const stats = {
    total: currentFiles.length,
    completed: currentFiles.filter(f => f.status === 'completed').length,
    savedBytes: currentFiles.reduce((acc, curr) => {
        if (curr.status === 'completed' && curr.processedSize) {
            return acc + (curr.originalSize - curr.processedSize);
        }
        return acc;
    }, 0)
  };

  const hasIdleOrError = currentFiles.some(f => f.status === 'idle' || f.status === 'error');
  const showReprocess = currentFiles.length > 0 && !hasIdleOrError;

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden relative">
      <SettingsPanel
        mode={mode}
        onModeChange={setMode}
        options={options}
        onOptionsChange={setOptions}
        pdfOptions={pdfOptions}
        onPdfOptionsChange={setPdfOptions}
        disabled={isProcessing || currentFiles.length === 0}
        onProcess={handleProcessAll}
        isProcessing={isProcessing}
        hasFiles={currentFiles.length > 0}
        showReprocess={showReprocess}
      />

      <div className="flex-1 flex flex-col min-w-0 h-full">
        <header className="flex items-center justify-between px-8 py-4 border-b border-slate-800 bg-slate-950/50 backdrop-blur-sm z-10">
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-3">
                <div className={`p-2 rounded-lg shadow-lg transition-colors ${mode === 'image' ? 'bg-blue-600 shadow-blue-500/20' : 'bg-red-600 shadow-red-500/20'}`}>
                {mode === 'image' ? <ImageIcon className="w-6 h-6 text-white" /> : <FileText className="w-6 h-6 text-white" />}
                </div>
                <div>
                <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
                    OptiBatch
                </h1>
                <p className="text-xs text-slate-500 font-medium">{mode === 'image' ? 'Image Bulk Processor' : 'PDF Bulk Optimizer'}</p>
                </div>
            </div>
          </div>

          <div className="flex items-center gap-4">
             {currentFiles.length > 0 && (
                <div className="hidden md:flex items-center gap-3 text-xs font-medium text-slate-400 mr-2 animate-in fade-in slide-in-from-top-4 duration-300">
                    <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-800/50 border border-slate-700/50 rounded-lg shadow-sm backdrop-blur-sm">
                        {mode === 'image' ? <ImageIcon className="w-3.5 h-3.5 text-blue-400" /> : <FileText className="w-3.5 h-3.5 text-red-400" />}
                        <span>Files: <span className="text-white font-bold ml-0.5">{stats.total}</span></span>
                    </div>
                    {stats.completed > 0 && (
                        <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-800/50 border border-slate-700/50 rounded-lg shadow-sm backdrop-blur-sm">
                            <CheckCircle2 className="w-3.5 h-3.5 text-green-400" />
                            <span>Done: <span className="text-white font-bold ml-0.5">{stats.completed}</span></span>
                        </div>
                    )}
                    {stats.savedBytes > 0 && (
                         <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-800/50 border border-slate-700/50 rounded-lg shadow-sm backdrop-blur-sm">
                            <TrendingDown className="w-3.5 h-3.5 text-emerald-400" />
                            <span>Saved: <span className="text-emerald-400 font-bold ml-0.5">{(stats.savedBytes / 1024 / 1024).toFixed(1)} MB</span></span>
                        </div>
                    )}
                </div>
             )}

            {stats.completed > 0 && (
                <button
                onClick={handleDownloadAll}
                disabled={isZipping || isProcessing}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg bg-slate-800 hover:bg-slate-700 transition-all text-sm font-medium disabled:opacity-70 ${mode === 'image' ? 'text-blue-400' : 'text-red-400'} border border-slate-700 hover:border-slate-600`}
                >
                {isZipping ? <Loader2 className="w-4 h-4 animate-spin" /> : <Download className="w-4 h-4" />}
                {isZipping ? 'Zipping...' : 'Download All'}
                </button>
            )}

            {currentFiles.length > 0 && (
                <button
                onClick={handleClearAll}
