import { PDFDocument } from 'pdf-lib';
import { PdfProcessingOptions, PdfItem } from '../types';

export const processPdf = async (
  item: PdfItem,
  options: PdfProcessingOptions
): Promise<Partial<PdfItem>> => {
  try {
    const arrayBuffer = await item.file.arrayBuffer();
    const originalDoc = await PDFDocument.load(arrayBuffer);

    // Create a new document to copy pages into. 
    // This is often more effective at removing metadata and unused objects 
    // than modifying the original document in place.
    const optimizedDoc = await PDFDocument.create();

    const pages = await optimizedDoc.copyPages(originalDoc, originalDoc.getPageIndices());
    pages.forEach((page) => optimizedDoc.addPage(page));

    // Basic compression by stripping unused objects and using object streams
    const pdfBytes = await optimizedDoc.save({
      useObjectStreams: true,
      addDefaultPage: false,
      updateFieldAppearances: false,
    });

    const blob = new Blob([pdfBytes], { type: 'application/pdf' });
    const processedUrl = URL.createObjectURL(blob);

    // Provide the original preview URL if it doesn't exist for the compare modal
    const previewUrl = URL.createObjectURL(item.file);

    return {
      status: 'completed',
      processedUrl,
      processedSize: blob.size,
      error: undefined,
    };
  } catch (err: any) {
    console.error("PDF Processing error:", err);
    return {
      status: 'error',
      error: err.message || 'PDF optimization failed',
    };
  }
};

