import { PDFDocument } from 'pdf-lib';
import { PdfProcessingOptions, PdfItem } from '../types';
// @ts-ignore
import * as pdfjs from 'pdfjs-dist';

// Configure PDF.js worker
pdfjs.GlobalWorkerOptions.workerSrc = `https://esm.sh/pdfjs-dist@${pdfjs.version}/build/pdf.worker.min.mjs`;

export const processPdf = async (
  item: PdfItem,
  options: PdfProcessingOptions
): Promise<Partial<PdfItem>> => {
  try {
    const arrayBuffer = await item.file.arrayBuffer();
    const originalDoc = await PDFDocument.load(arrayBuffer);

    // Default strategy: Metadata stripping and structural cleanup
    if (options.compressionLevel === 'low') {
        const optimizedDoc = await PDFDocument.create();
        const pages = await optimizedDoc.copyPages(originalDoc, originalDoc.getPageIndices());
        pages.forEach((page) => optimizedDoc.addPage(page));

        const pdfBytes = await optimizedDoc.save({
            useObjectStreams: true,
            addDefaultPage: false,
        });

        const blob = new Blob([pdfBytes], { type: 'application/pdf' });
        return {
            status: 'completed',
            processedUrl: URL.createObjectURL(blob),
            processedSize: blob.size,
            error: undefined,
        };
    }

    // High/Medium strategies involve more aggressive resource handling
    // For 'high', we use rasterization which converts pages to compressed JPEGs
    // This is the only way to GUARANTEE size reduction for already optimized/scanned PDFs in JS.
    if (options.compressionLevel === 'high') {
        const loadingTask = pdfjs.getDocument({ data: arrayBuffer });
        const pdf = await loadingTask.promise;
        const resultDoc = await PDFDocument.create();

        // Rasterization parameters based on quality
        const scale = 1.5; // Enough for readability, small enough for compression
        const quality = 0.5;

        for (let i = 1; i <= pdf.numPages; i++) {
            const page = await pdf.getPage(i);
            const viewport = page.getViewport({ scale });
            const canvas = document.createElement('canvas');
            const context = canvas.getContext('2d');

            if (!context) continue;

            canvas.height = viewport.height;
            canvas.width = viewport.width;

            await page.render({
                canvasContext: context,
                viewport: viewport,
            }).promise;

            // Convert to a compressed JPEG
            const imgData = canvas.toDataURL('image/jpeg', quality);
            const img = await resultDoc.embedJpg(imgData);

            const newPage = resultDoc.addPage([viewport.width, viewport.height]);
            newPage.drawImage(img, {
                x: 0,
                y: 0,
                width: viewport.width,
                height: viewport.height,
            });
        }

        const pdfBytes = await resultDoc.save({ useObjectStreams: true });
        const blob = new Blob([pdfBytes], { type: 'application/pdf' });

        return {
            status: 'completed',
            processedUrl: URL.createObjectURL(blob),
            processedSize: blob.size,
            error: undefined,
        };
    }

    // Medium strategy: Enhanced structural cleanup
    const optimizedDoc = await PDFDocument.create();
    const pages = await optimizedDoc.copyPages(originalDoc, originalDoc.getPageIndices());
    pages.forEach((page) => optimizedDoc.addPage(page));

    // Save with aggressive stream compression
    const pdfBytes = await optimizedDoc.save({
        useObjectStreams: true,
        addDefaultPage: false,
        updateFieldAppearances: false,
    });

    const blob = new Blob([pdfBytes], { type: 'application/pdf' });
    const processedUrl = URL.createObjectURL(blob);

    return {
      status: 'completed',
      processedUrl,
      processedSize: blob.size,
      error: undefined,
    };
  } catch (err: any) {
    console.error("PDF Processing error:", err);
    return {
      status: 'error',
      error: err.message || 'PDF optimization failed',
    };
  }
};

import React, { useRef, useEffect } from 'react';
import { X, FileText, Info, AlertTriangle } from 'lucide-react';
import { formatBytes } from '../utils/imageUtils';

interface ComparePdfModalProps {
  originalUrl: string;
  processedUrl: string;
  originalSize: number;
  processedSize: number;
  onClose: () => void;
  fileName: string;
}

const ComparePdfModal: React.FC<ComparePdfModalProps> = ({ 
  originalUrl, 
  processedUrl, 
  originalSize,
  processedSize,
  onClose, 
  fileName 
}) => {
  const leftRef = useRef<HTMLIFrameElement>(null);
  const rightRef = useRef<HTMLIFrameElement>(null);

  // Synchronized scrolling attempt (only works if browsers allow access to iframe content)
  // Since these are Blob URLs on the same origin, it should work.
  useEffect(() => {
    const handleScrollSync = (source: HTMLIFrameElement, target: HTMLIFrameElement) => {
        try {
            const sourceDoc = source.contentDocument || source.contentWindow?.document;
            const targetDoc = target.contentDocument || target.contentWindow?.document;

            if (sourceDoc && targetDoc) {
                const scrollHandler = () => {
                    const scrollPercent = sourceDoc.documentElement.scrollTop / (sourceDoc.documentElement.scrollHeight - sourceDoc.documentElement.clientHeight);
                    const targetScroll = scrollPercent * (targetDoc.documentElement.scrollHeight - targetDoc.documentElement.clientHeight);
                    targetDoc.documentElement.scrollTop = targetScroll;
                };
                sourceDoc.addEventListener('scroll', scrollHandler);
                return () => sourceDoc.removeEventListener('scroll', scrollHandler);
            }
        } catch (e) {
            // Likely cross-origin or PDF viewer internal restrictions
            console.debug("Scroll sync not supported by this PDF viewer");
        }
    };

    const cleanupLeft = leftRef.current && rightRef.current ? handleScrollSync(leftRef.current, rightRef.current) : null;
    const cleanupRight = leftRef.current && rightRef.current ? handleScrollSync(rightRef.current, leftRef.current) : null;

    return () => {
        if (cleanupLeft) cleanupLeft();
        if (cleanupRight) cleanupRight();
    };
  }, []);

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-950/90 backdrop-blur-md animate-in fade-in duration-200" onClick={onClose}>
      <div 
        className="relative bg-slate-900 border border-slate-700 rounded-xl shadow-2xl w-full max-w-7xl h-[95vh] flex flex-col overflow-hidden"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between p-4 border-b border-slate-800 bg-slate-900/50 z-20">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-red-500/10 rounded-lg text-red-400">
                <FileText className="w-5 h-5" />
              </div>
              <div>
                <h3 className="font-semibold text-slate-200">PDF Quality Comparison</h3>
                <p className="text-xs text-slate-500 max-w-[200px] sm:max-w-md truncate">{fileName}</p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-4">
            {processedSize > originalSize && (
                <div className="hidden lg:flex items-center gap-2 px-3 py-1.5 bg-amber-500/10 border border-amber-500/20 rounded-lg text-[10px] text-amber-400">
                    <AlertTriangle className="w-3.5 h-3.5" />
                    Structural rebuild increased size slightly
                </div>
            )}
            <div className="hidden md:flex items-center gap-2 px-3 py-1.5 bg-blue-500/10 border border-blue-500/20 rounded-lg text-[10px] text-blue-300">
               <Info className="w-3.5 h-3.5" />
               Compare readability & layout fidelity
            </div>
            <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400 hover:text-white transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>
        </div>

        {/* Comparison Area */}
        <div className="flex-1 flex flex-row divide-x divide-slate-800 bg-slate-950 overflow-hidden">
          {/* Original View */}
          <div className="flex-1 flex flex-col min-w-0">
            <div className="bg-slate-900/80 px-4 py-2 border-b border-slate-800 flex justify-between items-center shrink-0">
               <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Original Document</span>
               <span className="text-[10px] font-mono text-slate-500">{formatBytes(originalSize)}</span>
            </div>
            <div className="flex-1 bg-slate-800 relative">
               <iframe 
                 ref={leftRef}
                 src={`${originalUrl}#toolbar=0&navpanes=0&view=FitH`} 
                 className="w-full h-full border-none"
                 title="Original PDF"
               />
               <div className="absolute bottom-4 left-4 pointer-events-none px-2 py-1 bg-black/40 rounded text-[9px] text-white/50 border border-white/5">
                    Original
               </div>
            </div>
          </div>

          {/* Optimized View */}
          <div className="flex-1 flex flex-col min-w-0">
            <div className="bg-slate-900/80 px-4 py-2 border-b border-slate-800 flex justify-between items-center shrink-0">
               <span className="text-[10px] font-bold text-blue-400 uppercase tracking-widest">Optimized Document</span>
               <div className="flex items-center gap-2">
                   <span className="text-[10px] font-mono text-blue-300">{formatBytes(processedSize)}</span>
                   <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded border ${processedSize < originalSize ? 'bg-green-500/10 text-green-400 border-green-500/20' : 'bg-slate-800 text-slate-500 border-slate-700'}`}>
                    {processedSize < originalSize ? `-${Math.round(((originalSize - processedSize) / originalSize) * 100)}%` : 'No Change'}
                   </span>
               </div>
            </div>
            <div className="flex-1 bg-slate-800 relative">
               <iframe 
                 ref={rightRef}
                 src={`${processedUrl}#toolbar=0&navpanes=0&view=FitH`} 
                 className="w-full h-full border-none"
                 title="Optimized PDF"
               />
               <div className="absolute bottom-4 right-4 pointer-events-none px-2 py-1 bg-blue-600/40 rounded text-[9px] text-white border border-blue-500/20">
                    Optimized
               </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

