  onProcess,
  isProcessing,
  hasFiles,
  showReprocess = false,
}) => {
  const handleChange = <K extends keyof ProcessingOptions>(
    key: K,
    value: ProcessingOptions[K]
  ) => {
    if (key === 'resizeMode') {
