import { PDFDocument } from 'pdf-lib';
import { PdfProcessingOptions, PdfItem } from '../types';
// @ts-ignore
import * as pdfjs from 'pdfjs-dist';

// Configure PDF.js worker
pdfjs.GlobalWorkerOptions.workerSrc = `https://esm.sh/pdfjs-dist@${pdfjs.version}/build/pdf.worker.min.mjs`;

export const processPdf = async (
  item: PdfItem,
  options: PdfProcessingOptions
): Promise<Partial<PdfItem>> => {
  try {
    const arrayBuffer = await item.file.arrayBuffer();

    // Low and Medium strategies handle document structure
    if (options.compressionLevel !== 'high') {
        const originalDoc = await PDFDocument.load(arrayBuffer);
        const optimizedDoc = await PDFDocument.create();
        const pages = await optimizedDoc.copyPages(originalDoc, originalDoc.getPageIndices());
        pages.forEach((page) => optimizedDoc.addPage(page));

        const pdfBytes = await optimizedDoc.save({
            useObjectStreams: true,
            addDefaultPage: false,
            // Medium strips more metadata
            updateFieldAppearances: options.compressionLevel === 'low',
        });

        const blob = new Blob([pdfBytes], { type: 'application/pdf' });
        return {
            status: 'completed',
            processedUrl: URL.createObjectURL(blob),
            processedSize: blob.size,
            error: undefined,
        };
    }

    // High strategy: Aggressive Rasterization
    // This converts pages to compressed JPEGs to guarantee size reduction
    const loadingTask = pdfjs.getDocument({ data: arrayBuffer });
    const pdf = await loadingTask.promise;
    const resultDoc = await PDFDocument.create();

    const scale = options.scale; 
    const quality = options.quality;

    for (let i = 1; i <= pdf.numPages; i++) {
        const page = await pdf.getPage(i);
        const viewport = page.getViewport({ scale });
        const canvas = document.createElement('canvas');
        const context = canvas.getContext('2d');

        if (!context) continue;

        canvas.height = viewport.height;
        canvas.width = viewport.width;

        await page.render({
            canvasContext: context,
            viewport: viewport,
        }).promise;

        // Convert to a compressed JPEG Blob
        const blob = await new Promise<Blob | null>((resolve) => {
            canvas.toBlob((b) => resolve(b), 'image/jpeg', quality);
        });

        if (blob) {
            const imgBytes = await blob.arrayBuffer();
            const img = await resultDoc.embedJpg(imgBytes);

            const newPage = resultDoc.addPage([viewport.width, viewport.height]);
            newPage.drawImage(img, {
                x: 0,
                y: 0,
                width: viewport.width,
                height: viewport.height,
            });
        }
    }

    const pdfBytes = await resultDoc.save({ 
        useObjectStreams: true,
        addDefaultPage: false 
    });

    const finalBlob = new Blob([pdfBytes], { type: 'application/pdf' });

    return {
        status: 'completed',
        processedUrl: URL.createObjectURL(finalBlob),
        processedSize: finalBlob.size,
        error: undefined,
    };
  } catch (err: any) {
    console.error("PDF Processing error:", err);
    return {
      status: 'error',
      error: err.message || 'PDF optimization failed',
    };
  }
};

