import React, { useRef, useEffect, useState } from 'react';
import { X, FileText, Info, AlertTriangle, Loader2, ChevronLeft, ChevronRight } from 'lucide-react';
import { formatBytes } from '../utils/imageUtils';
// @ts-ignore
import * as pdfjs from 'pdfjs-dist';

interface ComparePdfModalProps {
  originalUrl: string;
  processedUrl: string;
  originalSize: number;
  processedSize: number;
  onClose: () => void;
  fileName: string;
}

const ComparePdfModal: React.FC<ComparePdfModalProps> = ({ 
  originalUrl, 
  processedUrl, 
  originalSize,
  processedSize,
  onClose, 
  fileName 
}) => {
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(0);
  const [error, setError] = useState<string | null>(null);

  const leftCanvasRef = useRef<HTMLCanvasElement>(null);
  const rightCanvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Configure PDF.js worker
    pdfjs.GlobalWorkerOptions.workerSrc = `https://esm.sh/pdfjs-dist@${pdfjs.version}/build/pdf.worker.min.mjs`;

    let isMounted = true;

    const renderPages = async () => {
      setLoading(true);
      setError(null);
      try {
        const [originalPdf, processedPdf] = await Promise.all([
          pdfjs.getDocument(originalUrl).promise,
          pdfjs.getDocument(processedUrl).promise
        ]);

        if (!isMounted) return;

        setTotalPages(originalPdf.numPages);
        const pageNum = Math.min(currentPage, originalPdf.numPages);

        const [pageOrig, pageProc] = await Promise.all([
          originalPdf.getPage(pageNum),
          processedPdf.getPage(pageNum)
        ]);

        // Use a high scale to see compression artifacts clearly
        const scale = 2.0;
        const viewportOrig = pageOrig.getViewport({ scale });
        const viewportProc = pageProc.getViewport({ scale });

        if (leftCanvasRef.current && rightCanvasRef.current && isMounted) {
          const canvasOrig = leftCanvasRef.current;
          const canvasProc = rightCanvasRef.current;

          canvasOrig.height = viewportOrig.height;
          canvasOrig.width = viewportOrig.width;
          canvasProc.height = viewportProc.height;
          canvasProc.width = viewportProc.width;

          const renderCtxOrig = canvasOrig.getContext('2d');
          const renderCtxProc = canvasProc.getContext('2d');

          if (renderCtxOrig && renderCtxProc) {
            await Promise.all([
              pageOrig.render({ canvasContext: renderCtxOrig, viewport: viewportOrig }).promise,
              pageProc.render({ canvasContext: renderCtxProc, viewport: viewportProc }).promise
            ]);
          }
        }
      } catch (err: any) {
        console.error("PDF Render Error:", err);
        setError("Failed to render PDF preview. Browser might be blocking data access.");
      } finally {
        if (isMounted) setLoading(false);
      }
    };

    renderPages();

    return () => {
      isMounted = false;
    };
  }, [originalUrl, processedUrl, currentPage]);

  const handlePageChange = (delta: number) => {
    setCurrentPage(prev => Math.max(1, Math.min(totalPages, prev + delta)));
  };

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-950/95 backdrop-blur-xl animate-in fade-in duration-200" onClick={onClose}>
      <div 
        className="relative bg-slate-900 border border-slate-700 rounded-2xl shadow-2xl w-full max-w-[95vw] h-[92vh] flex flex-col overflow-hidden"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between p-4 border-b border-slate-800 bg-slate-900/80 z-20">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-red-500/10 rounded-xl text-red-400">
                <FileText className="w-5 h-5" />
              </div>
              <div>
                <h3 className="font-bold text-slate-100">Visual Quality Comparison</h3>
                <p className="text-xs text-slate-500 max-w-[200px] sm:max-w-md truncate font-medium">{fileName}</p>
              </div>
